const e=[{id:1,title:"上海往事之当年情",cover:"38.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e398cb38b257828eeedbcaa0ae2856da/manifest/video.m3u8",category:"爱情剧情",tags:["国产","电影","爱情","剧情","年代","上海","怀旧"],rating:"9.7",views:13366,duration:"13:08",description:"跨越三十年的爱恋，在动荡的上海滩，谱写一曲时代与个人的命运悲欢。",review:"画面精美，年代感还原极致，宛如一幅流动的上海风情画卷。爱情故事缠绵悱恻，与家国命运紧密相连，情感厚重而克制，令人潸然泪下。",region:"国产",type:"电影",year:2016,genre:"爱情剧情 / 年代传奇 / 都市怀旧",relatedIds:["0021","0042","0019","0059","0072","0002"],publishDate:"2024-01-01",summary:"影片以倒叙方式，讲述了一段跨越上世纪三十年代至六十年代的上海情缘。1937年的上海，银行家之子顾维钧与进步女学生苏雯因一场音乐会相识相知，炽热的爱情在战火阴云下悄然生长。淞沪会战爆发，顾维钧家族企业内迁，两人被迫分离，约定战后重聚。此后经历抗战、内战、时代变迁，两人各自在命运洪流中浮沉，一次次擦肩而过。顾维钧成为海外归来的爱国商人，苏雯则在教育岗位上默默奉献。三十年后，在上海的老街改造中，两鬓斑白的他们因一处旧居的归属问题再次相遇。尘封的记忆与未曾熄灭的情愫，在熟悉的城市风景中缓缓苏醒，诉说着那份被时代深深烙印的“当年情”。"},{id:2,title:"中国诗词大会第二季",cover:"31.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/77ae15566dde5cfb920bae4712a38399/manifest/video.m3u8",category:"纪录片",tags:["国产","电影","纪录片","文化","诗词","竞赛","励志"],rating:"8.6",views:18161,duration:"15:07",description:"镜头深入台前幕后，记录平凡人因诗词而闪光的热血征程与人文温度。",review:"视角独特，情感饱满。将竞赛的紧张与文化的厚重、个人的梦想与时代的脉搏完美结合，让观众在享受诗词之美的同时，更深刻地感受到中华文化的生命力和感染力。",region:"国产",type:"电影",year:2023,genre:"纪录片 / 文化纪实 / 竞赛励志",relatedIds:["0082","0073","0085","0057","0061","0010"],publishDate:"2024-01-01",summary:"本片并非综艺节目的简单剪辑，而是一部以电影视角深度跟拍《中国诗词大会》第二季制作过程与选手故事的纪录片。影片跟随来自天南海北、各行各业的参赛者：有坚守讲台的乡村教师，有与病魔抗争的乐观少年，有默默无闻的快递小哥，也有博闻强记的国学博士。镜头不仅记录他们在舞台上精彩激烈的对决，更深入他们的日常生活，探寻他们与诗词结缘的动人故事，展现诗词如何给予他们力量、慰藉与梦想。同时，影片也揭开了节目制作的幕后艰辛，从出题组的字斟句酌，到舞台设计的匠心独运，呈现出一群文化工作者为传承古典之美所付出的努力。这是一曲关于热爱、坚持与文化传承的赞歌。"},{id:3,title:"太平间闹鬼事件2：佐治亚鬼屋事件",cover:"84.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/41cb67b47a3668efaea014219666e659/manifest/video.m3u8",category:"恐怖惊悚",tags:["欧美","电影","恐怖","惊悚","灵异","真实改编","家庭"],rating:"9.5",views:17759,duration:"13:25",description:"搬入梦想之屋的一家人，逐渐发现这所房子隐藏着吞噬快乐的黑暗历史。",review:"影片基于知名都市传说改编，恐怖氛围营造出色，Jump Scare使用克制而有效。更侧重于家庭情感在恐怖危机中的纽带作用，使得惊吓之外不乏温情与力量。",region:"欧美",type:"电影",year:2016,genre:"恐怖惊悚 / 灵异事件 / 家庭剧情",relatedIds:["0088","0079","0051","0052","0054","0068"],publishDate:"2024-01-02",summary:"怀亚特一家为了新生活，搬进了佐治亚州乡间一栋价格低廉的美丽大宅。然而入住不久，怪事接连发生：小女儿总说有个“悲伤的叔叔”在跟她说话；屋内温度莫名骤降；深夜里传来清晰的脚步声与孩子的哭泣声。母亲莉莎开始调查房子的历史，惊恐地发现这里曾是一家殡仪馆，更在几十年前发生过灭门惨案。灵异现象愈演愈烈，威胁到每个家庭成员的安全。在驱魔师和灵异调查员的帮助下，他们逐渐揭开了房屋的恐怖真相：一个因极大痛苦和冤屈而滞留在原地的恶灵，正试图将怀亚特一家拖入它永恒的悲惨轮回之中。他们必须找到让恶灵安息的方法，否则将成为这所房子历史的一部分。"},{id:4,title:"天堂岛疑云第十三季",cover:"44.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/31227358d3c181b7168e28ad248cfb4e/manifest/video.m3u8",category:"悬疑探案",tags:["欧美","电影","悬疑","探案","喜剧","风光","系列"],rating:"8.8",views:7528,duration:"10:41",description:"阳光沙滩下的天堂小岛，再次发生离奇命案，警探们面临前所未有的复杂谜团。",review:"延续了系列轻松诙谐与扎实探案结合的特有风格。本季案件构思更为精巧，人物关系网络复杂，在迷人的热带风光中上演了一出悬念迭起的阿加莎式谋杀谜案。",region:"欧美",type:"电影",year:2024,genre:"悬疑探案 / 喜剧 / 剧情",relatedIds:["0030","0055","0042","0027","0081","0039"],publishDate:"2024-01-02",summary:"在风景如画的加勒比海圣玛丽岛，看似平静的度假天堂再次被谋杀案打破宁静。一名在岛上举办奢华婚礼的知名科技富豪，于新婚之夜死在布置华丽的洞房中，死因离奇。总督察内维尔·帕克与团队展开调查，却发现所有宾客——包括新娘、家人、商业伙伴乃至旧情人——都与死者有着错综复杂的利益与情感纠葛，人人都有动机。与此同时，一桩看似无关的古老海盗宝藏传说，却与当下的案件产生了隐秘的联系。在碧海蓝天的反差背景下，帕克和他的搭档们必须拨开重重谎言与误导，在充满异域风情的环境中，破解这起融合了现代金钱阴谋与历史传奇阴影的双重谜案。"},{id:5,title:"冒牌财阀是大佬",cover:"5.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/d0af4221b8947fda8c23f4955947cb58/manifest/video.m3u8",category:"爱情喜剧",tags:["日韩","电影","爱情","喜剧","都市","身份错位","甜宠"],rating:"8.6",views:16340,duration:"15:44",description:"小职员被迫假扮财阀总裁，却遇上了受命来调查他的“未婚妻”。",review:"经典身份错位梗玩出了新意，喜剧效果拉满。男女主角颜值与演技在线，互动甜蜜搞笑，剧情轻松下饭，是合格的浪漫喜剧爆米花电影。",region:"日韩",type:"电影",year:2021,genre:"爱情喜剧 / 都市浪漫 / 身份错位",relatedIds:["0095","0060","0068","0066","0088","0006"],publishDate:"2024-01-03",summary:"大型集团底层职员李俊河，因与失踪的财阀继承人长得一模一样，被集团会长（继承人的爷爷）秘密找上，要求他在找到真继承人前假扮总裁，以稳定局势。俊河战战兢兢地扮演着霸道总裁，闹出不少笑话。与此同时，商业对手的女儿姜瑞妍，被父亲派来接近“假总裁”以获取商业机密。瑞妍怀着目的接近，却发现这个“总裁”毫无架子，甚至有些笨拙的可爱。两人在试探与伪装中互生情愫。然而，真继承人的消息传来，俊河的冒牌身份及瑞妍的初始目的即将暴露，这段建立在谎言之上的感情，面临着严峻考验。最终，俊河凭借自己的真诚与智慧，不仅化解了危机，更赢得了真正的尊重与爱情。"},{id:6,title:"工会成员",cover:"42.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e70b98acb53eb889d108057988609efb/manifest/video.m3u8",category:"剧情",tags:["欧美","电影","剧情","传记","工会","社会","抗争"],rating:"9.7",views:10746,duration:"10:07",description:"一位普通女工如何挺身而出，领导一场改变历史的汽车工厂罢工运动。",review:"表演真挚有力，尤其是女主角的演绎极具说服力。影片冷静而克制地重现了历史时刻，叙事扎实，情感充沛，是对平凡英雄及其所代表的集体力量的一次深刻致敬。",region:"欧美",type:"电影",year:2020,genre:"剧情 / 传记 / 社会纪实",relatedIds:["0097","0069","0037","0033","0094","0071"],publishDate:"2024-01-03",summary:"影片根据真实事件改编，聚焦上世纪70年代美国汽车工业重镇。性格坚毅的单身母亲艾丽斯是汽车装配线上的一名普通女工，每日忍受着高强度劳动、性别歧视和不公的待遇。当公司宣布新一轮残酷的裁员和降薪计划时，长期被男性和资方把持的工会却无所作为。忍无可忍的艾丽斯站了出来，她联合其他被忽视的女性工人和少数族裔工人，克服内部纷争与外部威胁，勇敢地组织起一场史无前例的、由基层工人主导的大罢工。她们不仅要对抗强大的资本，还要挑战工会内部的腐败与僵化体制。这场罢工不仅关乎经济权益，更是一场为尊严与平等而战的运动，最终深刻影响了美国劳工权益的进程。"},{id:7,title:"洛杉矶无人行走",cover:"52.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/86ea18f9954dbaf22eff5e16c41b4a25/manifest/video.m3u8",category:"科幻悬疑",tags:["欧美","电影","科幻","悬疑","心理","惊悚","末世感"],rating:"9.3",views:13994,duration:"17:07",description:"一觉醒来，他发现喧嚣的洛杉矶空无一人，自己成了城市唯一的活物。",review:"影片以极高的概念设定和氛围营造取胜，将现代都市的寂寥感放大到极致。男主角的独角戏极具挑战性，心理变化层次丰富，引导观众一同陷入对存在与孤独的哲学思考。",region:"欧美",type:"电影",year:2023,genre:"科幻悬疑 / 剧情 / 心理惊悚",relatedIds:["0039","0079","0011","0005","0096","0073"],publishDate:"2024-01-04",summary:"平凡的剧本作家马克在洛杉矶的公寓中醒来，发现世界变得异常安静。他走到窗前，平日车水马龙的街道空荡无人，所有车辆停摆，通讯中断，整座城市仿佛被按下了静音键。没有尸体，没有灾难迹象，人类如同凭空蒸发。起初，马克享受这无尽的自由与资源，但孤独与恐惧很快将他吞噬。他开始在空城中寻找线索，通过留下的日记、监控碎片和广播杂音，拼凑出一个令人不安的事实：似乎只有他被“选中”留下。而更可怕的是，他逐渐感觉到，自己并非真正独处——某种无形的存在，或是一个难以理解的庞大实验，正以这座空城为舞台，观察着他的一举一动。他的理智开始走向崩溃边缘。"},{id:8,title:"地狱保安",cover:"34.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/2df81e778442675885257ce3e84c7173/manifest/video.m3u8",category:"奇幻喜剧",tags:["国产","电影","奇幻","喜剧","动作","地狱","保安"],rating:"9.2",views:6949,duration:"16:15",description:"失业拳手应聘成高档小区保安，却发现业主都不是人，他是维护阴阳平衡的最后防线。",review:"将中国传统志怪元素与现代都市喜剧巧妙混搭，创意十足。笑点密集又不乏温馨，动作设计结合了功夫与法术，趣味横生，是一部成功的商业类型片探索。",region:"国产",type:"电影",year:2022,genre:"奇幻喜剧 / 动作冒险 / 都市怪谈",relatedIds:["0034","0051","0022","0061","0012","0098"],publishDate:"2024-01-04",summary:"前职业拳手张猛失业后，勉强应聘上“幽兰苑”高档小区的夜班保安。上班第一天，他就发现小区怪事连连：遛狗的老太太牵着三头犬，晚归的女士脚不沾地，新搬来的邻居总在院子里烧奇怪的东西。原来，“幽兰苑”是地狱驻人间办事处，住户都是等待轮回或执行公务的“非人”存在。张猛本想辞职，却因阳气极旺被小区“管理处”（实为阎王下属）强行留下，成为维护阴阳平衡、防止“厉鬼”扰民的唯一人选。从此，他白天补觉，晚上则用拳脚和桃木剑，处理各种令人啼笑皆非的灵异纠纷，从调解僵尸夫妻吵架，到追捕越狱的调皮小妖，成了名副其实的“地狱保安”。"},{id:9,title:"这个女孩很厉害",cover:"75.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/af3d3f3b4940cee04efcd8ff2c9eef0a/manifest/video.m3u8",category:"校园青春",tags:["国产","电影","校园","青春","励志","运动","成长"],rating:"9.1",views:7724,duration:"14:22",description:"转学而来的“问题少女”，用野路子拳法打入男子拳击社，挑战所有人的偏见。",review:"充满热血与反叛精神，女主角形象飒爽立体。拳击场面真实有力，校园生活描绘生动，主题积极向上，是一部能点燃观众激情、打破刻板印象的优秀青春片。",region:"国产",type:"电影",year:2024,genre:"校园青春 / 运动励志 / 成长剧情",relatedIds:["0070","0057","0059","0071","0049","0053"],publishDate:"2024-01-05",summary:"从小在街头摸爬滚打、练就一身野拳法的林晓雨，转学到一所纪律严明的高中。因多次打架被贴上“问题少女”标签。偶然间，她发现了学校的男子拳击社，燃起兴趣，却因性别被拒之门外。不服输的晓雨直接挑战拳击社社长——校草兼优等生周亦扬，并在众目睽睽下以刁钻的街头打法将其击倒，震惊全校。以此为契机，她破格入社，但迎接她的是社员的排斥、校方的压力以及传统训练与野路子的冲突。在备战全市高中拳击联赛的过程中，晓雨不仅用实力赢得了尊重，她那不拘一格的打法也为陷入瓶颈的拳击社带来了新的活力。最终，她和队友们共同在赛场上，打破了性别与出身的偏见，找到了属于自己的荣耀。"},{id:10,title:"侠义神捕之请君入瓮",cover:"90.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/60b4ddb3d166e1239abfc7adf611a6a3/manifest/video.m3u8",category:"古装动作",tags:["国产","电影","古装","动作","悬疑","探案","武侠"],rating:"8.7",views:6220,duration:"17:00",description:"神捕设下精妙陷阱追查飞贼，却发现贼影背后牵连着一桩惊天冤案。",review:"剧情一波三折，反转巧妙。既有精彩的古装动作场面，又有抽丝剥茧的探案过程。对“法”与“情”、“侠”与“捕”的冲突刻画深刻，提升了影片的思想内涵。",region:"国产",type:"电影",year:2018,genre:"古装动作 / 悬疑探案 / 武侠",relatedIds:["0041","0065","0001","0097","0079","0072"],publishDate:"2024-01-05",summary:"京城屡现奇案，一蒙面飞贼“无影”专盗贪官污吏，留下劫富济贫的侠名，令官府颜面尽失。六扇门总捕头“铁面”司马追风奉命限期破案。他洞察“无影”行事规律，精心设计了一个“请君入瓮”的局，利用一份假贪官名录引其上钩。局成，“无影”果然中计被捕。然而，在审讯中，司马追风发现“无影”的真实身份竟是自己已故恩师的独子，而其所作所为，皆与一桩被掩盖多年的军饷贪污案有关，此案直接导致恩师蒙冤而死。一边是法理铁律，一边是恩义真相，司马追风陷入两难。最终，他决定与“无影”合作，表面上继续追捕，实则暗中调查，共同布局，将真正的幕后黑手——位高权重的朝中大佬，引入一个更大的“瓮”中。"},{id:11,title:"比利小子第二季",cover:"4.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/a27121d514ff0079e1e81a6678f14e0c/manifest/video.m3u8",category:"西部剧情",tags:["欧美","电影","西部","剧情","历史","传记","冒险"],rating:"9.8",views:10445,duration:"11:06",description:"传奇法外之徒比利小子，在逃亡路上卷入更大的土地与资本阴谋。",review:"制作精良，西部风光壮阔。本季格局更大，将个人传奇融入时代洪流，叙事更加沉稳深刻。主角形象更加复杂丰满，对西部拓荒史的阴暗面有更深入的揭示。",region:"欧美",type:"电影",year:2025,genre:"西部剧情 / 历史传记 / 冒险",relatedIds:["0071","0055","0078","0099","0008","0012"],publishDate:"2024-01-06",summary:"延续第一季剧情，比利小子在林肯郡战争后成为全国通缉的要犯，在西部广袤的土地上逃亡。然而，他很快发现，追捕他的不仅仅是治安官，还有势力庞大的铁路公司雇佣的武装侦探。公司为了低价攫取土地铺设铁路，不择手段地驱赶原著居民和小农场主。比利在一次躲避追捕中，意外救下了一个被公司暴力威胁的墨西哥裔家庭，并与他们结下友谊。他不再仅仅是那个为个人恩怨和生存而战的枪手，开始被迫审视这片土地上正在发生的、更为残酷和不公的掠夺。他利用自己的名声和机智，周旋于各方势力之间，从一名亡命徒，逐渐转变为弱势者反抗强权的象征，其传奇也被赋予了新的时代注脚。"},{id:12,title:"青之壬生狼",cover:"82.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/f0d38b8679a1231eff816a8e04cc1a0c/manifest/video.m3u8",category:"历史剧情",tags:["日韩","电影","历史","剧情","动作","武士","新撰组"],rating:"8.7",views:16988,duration:"14:43",description:"以新撰组天才剑士冲田总司的视角，重现幕末动乱中“诚”之组的荣耀与悲歌。",review:"画面极具美感，打斗场面华丽而富有仪式感。情感刻画细腻，从个人成长折射出时代的悲壮，成功塑造了一个既有天才锋芒又有少年柔情的冲田总司形象。",region:"日韩",type:"电影",year:2024,genre:"历史剧情 / 动作 / 武士",relatedIds:["0011","0052","0081","0075","0005","0008"],publishDate:"2024-01-06",summary:"幕末动乱的京都，少年剑术天才冲田总司加入浪士组（后为新撰组），身披青色羽织，与近藤勇、土方岁三等伙伴一同，立志以手中之剑维护京都治安，守护即将倾覆的德川幕府秩序。影片以冲田总司清澈又锐利的目光，见证这个传奇武装集团的崛起：池田屋事件的浴血奋战，内部的忠诚与背叛，以及在时代巨轮下的无力与挣扎。总司与同伴们的情谊，在一次次任务与危机中愈发坚固，而他自身也在飞速成长，剑技臻于化境，却不幸被病魔（肺结核）悄然侵蚀。当戊辰战争爆发，新撰组的命运走向终结，病重中的总司，在樱花纷飞中，回忆着那段如狼般迅猛、如青空般纯粹，却又注定消逝的青春与忠诚。"},{id:13,title:"神医下山，未婚妻闺蜜倒追我",cover:"66.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c66b5309b3b64d15ed856810d6cc0b72/manifest/video.m3u8",category:"都市情感",tags:["国产","电影","神医","都市","喜剧","情感纠葛"],rating:"9.2",views:19700,duration:"12:54",description:"神医出山履行婚约，却被未婚妻的强势闺蜜缠上，陷入啼笑皆非的三角恋。",review:"影片节奏明快，喜剧元素自然流畅，将传统神医题材与现代都市背景巧妙结合。人物设定鲜活有趣，尤其是秦岚倒追的桥段大胆新颖，情感转折细腻可信，在欢笑中探讨了爱情与婚姻的真谛。",region:"国产",type:"电影",year:2023,genre:"都市情感 / 喜剧 / 奇幻",relatedIds:["0078","0022","0045","0014","0031","0080"],publishDate:"2024-01-07",summary:"身怀绝技的隐世神医林风，奉师命下山与指腹为婚的苏家千金苏婉履行婚约。然而，性格强势、厌恶包办婚姻的苏婉对林风极为排斥。反倒是苏婉的闺蜜、商业女强人秦岚，在目睹林风以神乎其技的医术化解数次危机后，被他深藏不露的才华与质朴的人格魅力深深吸引，展开了一场热烈而大胆的倒追。林风夹在冷漠的未婚妻与热情的追求者之间，既要应对都市中的各种疑难杂症，也要处理这段错综复杂的情感关系，最终在嬉笑怒骂中寻得真爱的答案。"},{id:14,title:"两个遥远的陌生人",cover:"62.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c99d86ece73a935b77e57d322461ddb5/manifest/video.m3u8",category:"科幻",tags:["欧美","电影","科幻","平行宇宙","爱情","哲学思考"],rating:"9.0",views:14942,duration:"12:06",description:"两个生活在不同平行宇宙的陌生人，因一次量子纠缠，开始共享彼此的人生片段。",review:"设定极具创意，将硬核科幻概念与细腻情感叙事完美融合。影片节奏舒缓却充满张力，探讨了孤独、联系与存在的本质。两位主演的隔空互动演技精湛，情感渲染力极强。",region:"欧美",type:"电影",year:2021,genre:"科幻 / 剧情 / 爱情",relatedIds:["0086","0003","0023","0013","0004","0033"],publishDate:"2024-01-07",summary:"物理学家艾拉与远在另一个平行宇宙的建筑师利奥，因为一场意外的量子实验产生了意识纠缠。每天会有随机的一段时间，他们能感知到对方的视觉、听觉甚至部分记忆，如同灵魂短暂地寄居在另一个身体里。起初的恐慌与混乱过去后，他们开始通过留言和预设行动进行“隔空”交流。两个原本孤独的个体，在无法触及彼此世界的遥远距离中，建立了深刻的精神联结，并共同面对各自宇宙中的困境。最终，他们做出选择，试图在茫茫宇宙法则中寻找一线相遇的可能。"},{id:15,title:"战斗传教士",cover:"30.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fe0c41d994d01211debb24e84e3384a9/manifest/video.m3u8",category:"动作",tags:["日韩","电影","动作","救赎","黑帮","信仰冲突"],rating:"9.5",views:8698,duration:"13:40",description:"前黑帮金牌打手皈依后，为保护教会与孤儿院，不得不重拾尘封的武力。",review:"动作场面凌厉写实，与文戏的平静形成强烈反差，极具冲击力。主角内心的挣扎刻画得入木三分，信仰与暴力的主题发人深省，是一部超越类型片的深度动作剧情片。",region:"日韩",type:"电影",year:2019,genre:"动作 / 剧情 / 犯罪",relatedIds:["0099","0037","0018","0070","0029","0016"],publishDate:"2024-01-08",summary:"曾是东南亚黑帮顶级杀手的金哲秀，因一次任务导致无辜孩童丧生而心灵崩溃，逃亡至韩国偏远小镇，在一所教堂皈依并成为一名默默无闻的传教士。多年后，跨国犯罪集团为争夺教堂及孤儿院地下的矿产开采权，对这片净土步步紧逼。当和平的祈祷与谈判均告无效，看着神父和孩子们恐惧的眼神，哲秀内心经历着信仰与暴力的剧烈冲突。最终，为了保护最后的“圣所”与需要守护的人，他决定违背“不杀”的誓言，以“战斗传教士”的身份，用最熟悉也最憎恶的方式，进行一场神圣而残酷的清算。"},{id:16,title:"辞职后前妻追悔莫及",cover:"60.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/929fdb8e536c1fc43a83b32d1a838547/manifest/video.m3u8",category:"都市",tags:["国产","电影","都市","爱情","喜剧","逆袭","职场"],rating:"8.6",views:17099,duration:"15:52",description:"丈夫辞职投身冷门事业获巨大成功，一心追求事业的前妻才发现错过了宝藏。",review:"剧情贴近现实，人物塑造真实可信。男主逆袭的过程爽感十足，女主的心路历程转变细腻。影片在轻松喜剧的氛围下，探讨了婚姻中价值认同与相互理解的重要性。",region:"国产",type:"电影",year:2022,genre:"都市 / 爱情 / 轻喜剧",relatedIds:["0036","0060","0045","0054","0040","0078"],publishDate:"2024-01-08",summary:"陈默在一家跨国公司担任普通经理，为支持妻子沈薇的事业，多年来包揽家务、默默付出。沈薇却认为丈夫安于现状、不求上进，两人最终离婚。离婚后，陈默毅然辞职，投身于自己热爱的传统木艺修复，凭借过人才华与网络传播，竟成为国潮文化领域的顶尖人物，名利双收。而沈薇在事业巅峰遭遇重大挫折，偶然间看到关于陈默的专访，目睹他专注、自信且充满魅力的样子，回想起过去被他悉心照料的点点滴滴，悔恨如潮水般涌来。她开始尝试重新接近陈默，但破镜能否重圆？"},{id:17,title:"我以凡骨战神明",cover:"61.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fbc04ae173a0e633458658e80ee78c2a/manifest/video.m3u8",category:"奇幻",tags:["国产","电影","奇幻","热血","逆袭","东方玄幻"],rating:"9.0",views:9373,duration:"10:55",description:"天生无法修炼的“凡骨”少年，为守护家园，以血肉之躯向降临世间的神明发起挑战。",review:"设定颠覆传统修仙题材，将“凡人”置于故事核心，热血沸腾。动作设计充满想象力，将武术与策略结合对抗神通，视觉震撼。主题关于勇气与尊严，情感力量强大。",region:"国产",type:"电影",year:2024,genre:"奇幻 / 动作 / 热血",relatedIds:["0013","0041","0028","0031","0003","0025"],publishDate:"2024-01-09",summary:"在一个修仙者主宰的世界，少年林岩是罕见的“无灵根”凡骨，受尽冷眼。一日，名为“收割者”的异域神明降临，以众生灵力为食，修仙宗门在其面前不堪一击。当神明欲摧毁林岩所在的凡人城镇时，他发现自己的“凡骨”竟能免疫神明的灵力吸收。凭借此特性，以及多年来为弥补无法修仙而磨炼出的极致武技、坚韧意志和对家园的热爱，林岩手持凡铁，以最原始的战术，向高高在上的神明发起一场看似螳臂当车、却步步惊心的惨烈抗争。他的战斗，点燃了所有被忽视的凡人的勇气。"},{id:18,title:"超能立方·动态漫",cover:"8.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/0ba4f146b0e6ea192526706f495d460f/manifest/video.m3u8",category:"科幻",tags:["国产","电影","动画","科幻","超能力","团队冒险"],rating:"9.7",views:17892,duration:"16:41",description:"六个少年意外获得蕴含不同超能力的立方体，被迫卷入一场跨越维度的保卫战。",review:"动态漫画形式新颖，动作场面流畅炫酷，想象力爆棚。六人组的角色成长弧光完整，从各自为战到彼此信任的过程感人。科幻设定扎实，悬念层层递进。",region:"国产",type:"电影",year:2025,genre:"科幻 / 动画 / 冒险",relatedIds:["0081","0052","0047","0056","0040","0083"],publishDate:"2024-01-09",summary:"高中生韩星在旧货市场买回一个神秘金属立方体。某夜，立方体激活，赋予他操控电磁的能力，同时他也被来自高维空间的“清除者”追杀。他很快发现，还有另外五个散落在城市的立方体及持有者，分别掌握了空间、生命、力量、心灵、时间等不同维度的碎片能力。为了生存并解开立方体的起源之谜，六个性格、背景各异的少年被迫组成团队。他们不仅要学习掌控彼此冲突的超能力，协同作战，更要面对内部纷争与“清除者”的 relentless 猎杀，在一次次危机中成长，最终揭晓立方体是守护地球维度稳定的最后钥匙。"},{id:19,title:"路边捡个老公有亿点强",cover:"22.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1e53f0e1aef7ec2fb5f30ef5d309d69c/manifest/video.m3u8",category:"爱情",tags:["国产","电影","爱情","喜剧","奇幻","先婚后爱"],rating:"9.1",views:12107,duration:"12:15",description:"社畜女捡回一个失忆美男，却发现他是来自异世界的顶级强者，生活瞬间天翻地覆。",review:"甜宠与喜剧元素密集，男主“亿点强”的设定满足幻想，互动有趣。后期世界观展开带来剧情厚度，爱情线与冒险线结合得当，娱乐性十足。",region:"国产",type:"电影",year:2023,genre:"爱情 / 喜剧 / 奇幻",relatedIds:["0068","0039","0059","0077","0064","0098"],publishDate:"2024-01-10",summary:"普通上班族苏晓在下班路上“捡到”一个浑身是伤、失去记忆的英俊男人，于心不忍带回家照料，并戏称其为“老公”。男人逐渐恢复，展现出惊人的知识储备、战斗能力和神秘气质，帮苏晓解决了工作、生活中的诸多麻烦，感情日渐升温。然而，异世界追兵的到来揭开了男人的身份：他竟是那个世界叛乱中失踪的帝国战神凌昊天。苏晓平凡的世界被卷入巨大的漩涡，她必须在爱情的牵绊与跨越世界的危机中做出选择，而凌昊天也面临着回归责任还是守护眼前人的终极抉择。"},{id:20,title:"日落日出2024",cover:"80.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1116997bf50b78f22bbfaced8975a021/manifest/video.m3u8",category:"剧情",tags:["欧美","电影","剧情","家庭","公路","治愈"],rating:"8.7",views:6257,duration:"16:04",description:"一对关系破裂的父女，驾驶老旧的房车，踏上一场追寻极光的治愈之旅。",review:"影片节奏舒缓如一首散文诗，风景拍摄壮美动人。父女间的情感刻画极其细腻真实，表演克制而富有力量。是一部关于原谅、失去与珍惜的暖心治愈之作。",region:"欧美",type:"电影",year:2024,genre:"剧情 / 家庭 / 公路",relatedIds:["0009","0071","0066","0052","0077","0034"],publishDate:"2024-01-10",summary:"因童年创伤与母亲早逝，莎拉与父亲罗伯特关系冰冷疏远多年。2024年，退休的罗伯特被诊断出患有早期阿尔茨海默症，他买下一辆二手房车，恳求莎拉陪他完影视生最后的心愿：去冰岛看一次极光。带着复杂心情，莎拉不情愿地踏上旅程。在横跨北美前往冰岛的漫长公路上，两人被困在狭小空间内，被迫交流。从争吵到沉默，再到偶然分享回忆，旅途中的风景与意外事件逐渐融化坚冰。当终于目睹绚烂极光在夜空中舞动时，父女俩找到了与过去和解、珍惜此刻日出的方式。"},{id:21,title:"舒小姐你认错老公了",cover:"25.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e398cb38b257828eeedbcaa0ae2856da/manifest/video.m3u8",category:"爱情",tags:["国产","电影","爱情","喜剧","误会","契约婚姻"],rating:"9.3",views:18722,duration:"16:36",description:"为应付家族联姻，她随手拉个路人假扮老公，没想到拉来的竟是商界传奇本尊。",review:"误会式开场充满喜剧效果，契约婚姻的桥段经典却演绎出新意。男女主互动火花四溅，从针锋相对到逐渐动心的过程甜而不腻。剧情轻松欢快，是合格的下饭甜宠片。",region:"国产",type:"电影",year:2022,genre:"爱情 / 喜剧 / 都市",relatedIds:["0099","0031","0086","0093","0046","0069"],publishDate:"2024-01-11",summary:"舒家面临商业危机，要求女儿舒念联姻。为反抗命运，舒念在家族宴会上急中生智，拉住在酒店门口遇到的一个气质出众却衣着低调的男人，声称是自己“隐婚”的丈夫。男人配合演完了戏。事后舒念才惊恐地发现，这位“路人”竟是本市最神秘低调的商界巨鳄、顾氏集团掌门人顾霆深。顾霆深非但没有追究，反而提出一场各取所需的“契约婚姻”，帮她摆脱联姻，自己则借此避开烦人的桃花与家族逼婚。两人在同一屋檐下假装恩爱，却假戏真做，而舒念当初“认错”的背后，似乎也藏着顾霆深不为人知的刻意安排。"},{id:22,title:"森林的终点是海",cover:"69.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/77ae15566dde5cfb920bae4712a38399/manifest/video.m3u8",category:"剧情",tags:["日韩","电影","剧情","奇幻","成长","自然","治愈"],rating:"9.7",views:11427,duration:"14:26",description:"自闭症少年在森林中迷路，跟随一只会说话的狐狸，踏上一段寻找海洋的奇妙旅程。",review:"画面唯美如梦境，将森林的生机与神秘展现得淋漓尽致。奇幻设定服务于人物内心成长，情感真挚动人。是一部充满诗意与温柔力量的成长童话。",region:"日韩",type:"电影",year:2020,genre:"剧情 / 奇幻 / 成长",relatedIds:["0008","0081","0074","0026","0053","0088"],publishDate:"2024-01-11",summary:"患有自闭症的初中生小树，在学校郊游时于一片古老森林中走失。在他最恐惧无助时，遇到了一只自称“狐使”的会说话的白狐。白狐告诉他，森林的尽头是海，那里有能实现一个真诚愿望的“回音贝”。为了找到回家的路，也出于对海洋的纯粹向往，小树决定跟随狐使深入森林。旅途充满奇幻生物与自然奇观，也暗藏危险。不善言辞的小树在与狐使及途中生灵的互动中，缓慢地打开心扉，学会表达与信任。当他们终于穿越森林，见到浩瀚大海时，小树才发现，这段旅程本身就是最好的治愈与成长。"},{id:23,title:"熊熊乐园第一部",cover:"7.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/41cb67b47a3668efaea014219666e659/manifest/video.m3u8",category:"动画",tags:["国产","电影","动画","喜剧","冒险","合家欢"],rating:"10.0",views:10270,duration:"16:41",description:"调皮小熊布布误闯被遗忘的玩具乐园，与新朋友们展开一场守护家园的大冒险。",review:"动画制作精良，角色造型可爱，色彩鲜艳，非常适合低龄儿童观看。故事简单但充满正能量，强调友谊、勇气与团队合作。喜剧元素丰富，冒险情节紧张刺激又不失温馨。",region:"国产",type:"电影",year:2018,genre:"动画 / 喜剧 / 冒险 / 家庭",relatedIds:["0012","0067","0050","0063","0056","0019"],publishDate:"2024-01-12",summary:"活泼好动的小棕熊布布，在一次追逐蝴蝶的过程中，意外掉进树洞，发现了一个隐藏在山谷中的神奇地方——“熊熊乐园”。这里居住着许多被遗弃但拥有生命的毛绒玩具和动物玩偶。布布的到来带来了欢声笑语，也引来了觊觎乐园中“快乐能量”的反派玩具收藏家。收藏家派出机械玩具大军前来抓捕乐园居民。为了保卫新家园和朋友们，平时只会调皮捣蛋的布布，必须发挥自己的勇气和智慧，与机智的兔子绒绒、勇敢的泰迪熊阿木等伙伴团结一致，利用乐园里的各种设施和机关，展开一场妙趣横生又惊心动魄的防御战。"},{id:24,title:"暗夜孤院",cover:"95.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/31227358d3c181b7168e28ad248cfb4e/manifest/video.m3u8",category:"恐怖",tags:["欧美","电影","恐怖","悬疑","惊悚","心理","密闭空间"],rating:"9.0",views:9585,duration:"16:57",description:"一组心理研究员为验证理论，在废弃精神病院过夜，却遭遇超乎想象的恐怖事件。",review:"氛围营造顶级，将心理恐惧与实体恐怖结合得恰到好处。废弃医院的场景设计细节毛骨悚然。悬念层层推进，结局细思极恐，是近年优质的心理恐怖片。",region:"欧美",type:"电影",year:2017,genre:"恐怖 / 悬疑 / 惊悚",relatedIds:["0085","0067","0064","0096","0031","0054"],publishDate:"2024-01-12",summary:"一群心理学博士生在激进教授带领下，进入一座已废弃数十年的偏远精神病院，进行一项关于恐惧与集体潜意识的通宵实验。他们携带设备，计划记录在传闻闹鬼的环境中的生理心理数据。起初只是气氛压抑和些许异响，但随着夜幕加深，团队成员开始陆续产生强烈且个性化的幻觉，看到各自内心最深处的恐惧具象化。他们逐渐分不清幻觉与现实，彼此猜忌，陷入崩溃。教授惊恐地发现，这所医院的黑暗历史可能创造了一个吞噬负面情绪的实体，而他们的实验，恰好成为了唤醒它的“祭品”。必须在天亮前找到逃离或解决的方法。"},{id:25,title:"太子殿下今天破戒了吗",cover:"28.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/d0af4221b8947fda8c23f4955947cb58/manifest/video.m3u8",category:"古装",tags:["国产","电影","古装","爱情","喜剧","宫廷","甜宠"],rating:"9.7",views:13680,duration:"12:20",description:"被迫清修禁欲的傲娇太子，遇上专门负责“破戒”的欢脱小厨娘，内心防线全面崩塌。",review:"古装甜宠剧的轻松向佳作，人设反差萌十足，互动甜度超标。美食元素诱人，喜剧桥段自然不做作。剧情简单明快，是放松心情、感受甜蜜的优选。",region:"国产",type:"电影",year:2023,genre:"古装 / 爱情 / 喜剧",relatedIds:["0064","0042","0029","0037","0016","0070"],publishDate:"2024-01-13",summary:"东宫太子萧景煜因高僧批命，需茹素清修、戒急戒躁三年方可稳固国运，身边安排的皆是刻板严肃的仆从。新来的小厨娘叶笑笑，却是个阳光开朗、厨艺精湛、行事不按常理出牌的姑娘。她负责太子的素斋，却总能用奇思妙想做出令人食指大动的美食，并无意间打破太子诸多“不准”：不准笑、不准外出、不准亲近小动物……每次“破戒”都让太子的生活多了一抹色彩，也让他冷硬的心逐渐松动。而笑笑接近太子，似乎也藏着某个关于家族的小秘密。一场关于“戒律”与“本心”的甜蜜攻防战在深宫展开。"},{id:26,title:"我的助理不好惹",cover:"67.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e70b98acb53eb889d108057988609efb/manifest/video.m3u8",category:"职场",tags:["国产","电影","职场","喜剧","剧情","逆袭","女性"],rating:"9.9",views:18217,duration:"10:09",description:"空降高管本想欺负新助理立威，却不知对方是隐藏的业界传奇，反被教做人。",review:"职场逆袭剧情爽感十足，女主角深藏不露的设定非常带感。喜剧元素来源于男主“踢到铁板”的尴尬，轻松有趣。影片也侧面反映了职场生态与女性力量。",region:"国产",type:"电影",year:2021,genre:"职场 / 喜剧 / 剧情",relatedIds:["0027","0087","0063","0100","0039","0069"],publishDate:"2024-01-13",summary:"凭借关系空降到广告公司担任创意总监的张扬，为了树立威信，故意刁难分配给自己的助理、看似平凡温顺的姜晚。他扔给她不可能完成的任务，肆意批评她的方案。然而姜晚总是能默默交出远超预期的完美成果，一次次化解危机，无意中抢尽风头。张扬从恼怒到好奇，暗中调查，震惊地发现姜晚竟是业内早已封神的传奇文案“J”，因厌倦名利而隐居幕后。此时，公司面临重大危机，张扬不得不放下身段，真正请求姜晚出手。两人的关系从压迫与隐忍，转变为亦师亦友的合作伙伴，共同迎接挑战。"},{id:27,title:"芙蓉诀",cover:"72.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/86ea18f9954dbaf22eff5e16c41b4a25/manifest/video.m3u8",category:"古装",tags:["国产","电影","古装","武侠","爱情","江湖","恩怨"],rating:"9.2",views:9044,duration:"13:23",description:"背负灭门血仇的孤女，易容潜入仇家，却与仇人之子陷入无法自拔的爱恨纠缠。",review:"典型的武侠言情架构，但情节跌宕起伏，爱情线虐心感人。武侠场面设计飘逸有力度，服装布景颇具古典韵味。演员表演到位，将角色的矛盾与挣扎诠释得淋漓尽致。",region:"国产",type:"电影",year:2008,genre:"古装 / 武侠 / 爱情",relatedIds:["0004","0048","0071","0005","0056","0019"],publishDate:"2024-01-14",summary:"十五年前，武林世家芙蓉堡一夜覆灭，唯幼女秦芙被忠仆救出。十五年后，秦芙习得绝世武功与易容之术，化名“芙蓉”，以舞姬身份潜入当年主导灭门的凌天宫，伺机复仇。她成功引起少宫主凌无夜的注意，并成为其身边人。在朝夕相处中，凌无夜的正直、深情与对父辈所为的隐约质疑，动摇了秦芙复仇的决心。而凌无夜也在不知其真实身份的情况下，深深爱上了这个神秘而倔强的女子。当真相逐渐浮出水面，两人夹在血海深仇与刻骨爱情之间，面临最痛苦的抉择。最终，他们必须共同揭开当年惨案背后更大的阴谋。"},{id:28,title:"欢迎来到王之国",cover:"11.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/2df81e778442675885257ce3e84c7173/manifest/video.m3u8",category:"奇幻",tags:["日韩","电影","奇幻","喜剧","冒险","异世界","反差萌"],rating:"9.7",views:7181,duration:"18:37",description:"暴躁的韩国综艺PD意外穿越到以“快乐”为法则的童话王国，被迫成为快乐导师。",review:"设定新颖有趣，异世界与现实的碰撞制造了无数笑点。主角的成长弧光明显，从抗拒到融入的过程温暖治愈。是一部能让人开怀大笑又感受到温情的奇幻喜剧。",region:"日韩",type:"电影",year:2025,genre:"奇幻 / 喜剧 / 冒险",relatedIds:["0006","0070","0058","0022","0050","0011"],publishDate:"2024-01-14",summary:"以严苛和低情商著称的真人秀PD金哲秀，在节目录制事故中昏迷，醒来发现自己穿越到了一个奇异的“快乐王国”。这里的居民永远在微笑、唱歌、跳舞，法律只有一条：必须快乐，否则会被“忧愁警察”逮捕。金哲秀的暴躁与吐槽在这里成了重罪。为了生存并寻找回去的方法，他被迫接受国王的“改造”任务：用他制作综艺的经验，为王国策划一场史无前例的“终极快乐庆典”。于是，一个满脸写着不高兴的男人，带着一群过度快乐的“傻瓜”，开始了一场鸡飞狗跳、笑料百出的筹备之旅，过程中，金哲秀僵硬的心也悄然融化。"},{id:29,title:"圣诞故事",cover:"15.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/af3d3f3b4940cee04efcd8ff2c9eef0a/manifest/video.m3u8",category:"剧情",tags:["欧美","电影","剧情","家庭","奇幻","圣诞","治愈"],rating:"9.6",views:17548,duration:"15:43",description:"八岁的自闭症男孩在平安夜邂逅了一位自称是“替补圣诞老人”的落魄老人。",review:"影片温情脉脉，充满古典圣诞电影的魔力与治愈感。一老一少的互动真挚动人，表演细腻。故事强调了给予、分享与信念的力量，是适合全家观看的暖心佳作。",region:"欧美",type:"电影",year:2010,genre:"剧情 / 家庭 / 奇幻",relatedIds:["0017","0086","0043","0042","0088","0010"],publishDate:"2024-01-15",summary:"患有自闭症、几乎不与人交流的小男孩诺亚，在圣诞前夕随家人搬到新城市。他唯一的朋友是一本破旧的圣诞故事书。平安夜，诺亚在社区公园的长椅上，遇到了衣着单薄、正在吃剩三明治的老人尼克。尼克告诉诺亚，他是“第73号替补圣诞老人”，负责倾听那些被主名单遗漏的孩子们的愿望。诺亚被这个“童话”吸引，开始每天来找尼克“报告”他观察到的邻居们的烦恼。尼克则用他的人生智慧和一点小小的“魔法”，帮助诺亚间接地解决了这些问题。这段不可思议的友谊，不仅温暖了整个社区，也让诺亚紧闭的心门缓缓打开，给他的家庭带来了真正的圣诞奇迹。"},{id:30,title:"游龙戏凤",cover:"79.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/60b4ddb3d166e1239abfc7adf611a6a3/manifest/video.m3u8",category:"古装",tags:["国产","电影","古装","爱情","喜剧","宫廷","欢喜冤家"],rating:"9.0",views:6202,duration:"17:02",description:"风流王爷为避选妃装病逃宫，邂逅泼辣民女，展开一场身份错位的爆笑恋曲。",review:"典型的古装欢喜冤家套路，但执行得非常出色。男女主演技自然，化学反应强，对手戏火花四溅。喜剧桥段设计巧妙，宫廷与市井的反差制造了大量笑料，娱乐性很高。",region:"国产",type:"电影",year:2009,genre:"古装 / 爱情 / 喜剧",relatedIds:["0067","0058","0009","0045","0020","0049"],publishDate:"2024-01-15",summary:"当今圣上的胞弟逍遥王龙璟，风流倜傥，为躲避太后安排的选妃，假装身患怪病需出宫静养。他化名“龙三”，来到江南小镇。在此地，他偶遇了经营小酒馆、性格泼辣直爽的卖酒女凤舞。凤舞误将龙璟当作躲避赌债的落难公子，百般“嫌弃”却又好心收留。龙璟被凤舞的真性情与鲜活生命力吸引，乐得隐藏身份与她相处，闹出无数笑话。然而，太后的追兵、地方恶少的纠缠，以及龙璟真实身份的逐渐暴露，让这段纯粹的感情面临严峻考验。最终，龙璟必须在皇家责任与心之所向之间做出抉择。"},{id:31,title:"琴思",cover:"73.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/a27121d514ff0079e1e81a6678f14e0c/manifest/video.m3u8",category:"剧情",tags:["国产","电影","剧情","音乐","传记","民乐","传承"],rating:"10.0",views:10781,duration:"13:45",description:"天才古琴少女在追寻已故母亲琴声之谜的过程中，领悟音乐与生命的真谛。",review:"影片画面典雅，古琴曲贯穿始终，韵味悠长。故事双线叙事巧妙，将母女两代人的艺术追求与情感世界交织在一起。主题深刻，探讨了艺术传承、情感表达与生命意义。",region:"国产",type:"电影",year:2016,genre:"剧情 / 音乐 / 传记",relatedIds:["0040","0008","0063","0023","0048","0087"],publishDate:"2024-01-16",summary:"少年成名的古琴演奏家林思音，技艺高超却始终被认为“有技无情”。她的母亲、一代琴坛大家苏清影早逝，留下一张未曾完成的残谱和一把断弦的古琴。因一次演奏失利，思音陷入瓶颈，决定回到母亲生前最后居住的江南小镇，探寻母亲音乐与人生的秘密。在修复老琴、走访旧友、研究残谱的过程中，她逐渐拼凑出母亲晚年远离名利场、投身民乐教育、并与一位乡村木匠间真挚却无果的情感故事。母亲对音乐的理解从炫技转为述情，对生命从执着转为释然。思音终于在山水自然与人间烟火中，找到了属于自己的琴音，完成了母亲的残谱，也领悟了何谓“琴思”。"},{id:32,title:"周日晚上左右……",cover:"27.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/f0d38b8679a1231eff816a8e04cc1a0c/manifest/video.m3u8",category:"剧情",tags:["日韩","电影","剧情","爱情","生活流","治愈","都市"],rating:"8.7",views:14101,duration:"16:29",description:"每周日晚，七个陌生人在同一家咖啡馆相遇，分享彼此一周的故事与悲欢。",review:"典型的日式生活流电影，节奏舒缓，对白细腻。群像刻画生动，每个角色都令人印象深刻。影片捕捉了现代都市人的孤独与对连接的渴望，充满了温柔的人文关怀。",region:"日韩",type:"电影",year:2014,genre:"剧情 / 爱情 / 生活流",relatedIds:["0077","0006","0076","0098","0049","0037"],publishDate:"2024-01-16",summary:"在东京一家营业到深夜的街角咖啡馆“Sunday's”，每周日晚，七位背景各异的陌生人会不约而同地来到这里。有理发师、小说家、退休教师、公司职员、大学生、单亲妈妈和流浪歌手。他们起初只是各自占据一个角落，沉浸在自己的世界里。偶然的一次停电，打破了沉默，大家开始聊天。从此，每周日晚的咖啡馆成了他们固定的分享会。他们讲述一周的遭遇、工作的烦恼、隐秘的梦想、失去的爱情、小小的喜悦。没有惊天动地的故事，只有平淡真实的都市人生。在倾听与诉说中，七个孤独的灵魂慢慢靠近，彼此温暖，共同面对新一周的到来。"},{id:33,title:"一抹丹砂映清辉",cover:"18.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c66b5309b3b64d15ed856810d6cc0b72/manifest/video.m3u8",category:"古装",tags:["国产","电影","古装","权谋","悬疑","复仇","女性"],rating:"9.2",views:11480,duration:"15:59",description:"冷宫宫女额间一点朱砂，实为记录皇室秘辛的活密卷，引各方势力争夺。",review:"悬疑设定巧妙，将信息藏在人体刺青的创意十足。权谋线层层递进，紧张感把握得当。女主角从被动到主动的转变令人信服，是一部制作精良的古装悬疑片。",region:"国产",type:"电影",year:2022,genre:"古装 / 权谋 / 悬疑",relatedIds:["0054","0087","0070","0008","0099","0089"],publishDate:"2024-01-17",summary:"新帝登基，大赦后宫，一批年迈宫女得以出宫。其中一位名叫清辉的宫女，额间一点殷红朱砂痣，格外醒目。不久，多方神秘人马开始追踪这些离宫宫女，尤其是清辉。原来，二十年前，一场宫廷政变被掩盖，真相被当年尚是女官的清辉以特殊刺青秘术，化为一幅微缩地图，藏于额间朱砂之下。她自己则在事后被灌药失去部分记忆，贬入冷宫。如今，政变余党欲销毁证据，受害遗孤欲复仇雪恨，新帝欲查明先帝死因真相。失去记忆的清辉，在被动逃亡与主动探查中，逐渐拼凑起血腥往事，她的存在，成为搅动朝堂风云的关键。"},{id:34,title:"身份窃贼",cover:"2.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c99d86ece73a935b77e57d322461ddb5/manifest/video.m3u8",category:"犯罪",tags:["欧美","电影","犯罪","惊悚","剧情","身份盗用","悬疑"],rating:"9.9",views:14704,duration:"10:03",description:"普通上班族发现有人完美盗用自己身份生活，甚至替代他与家人朋友相处。",review:"题材贴近现代人的隐私焦虑，设定令人毛骨悚然。影片节奏紧凑，悬疑感从头到尾维持得非常好。主角的无力与挣扎让观众感同身受，结局反转出人意料。",region:"欧美",type:"电影",year:2013,genre:"犯罪 / 惊悚 / 剧情",relatedIds:["0051","0052","0063","0006","0059","0025"],publishDate:"2024-01-17",summary:"生活规律、性格温和的会计亨利，某天开始接到奇怪的催债电话和信用卡账单。起初他以为只是信息泄露，但情况急转直下：他的工作邮箱被黑，公寓有被闯入的痕迹，甚至朋友声称前几天刚与他喝过酒。亨利惊恐地意识到，有一个外貌与他极其相似的人，正在系统地、有条不紊地“覆盖”他的生活。这个“影子”不仅窃取他的财物，更在模仿他的言行，接触他的亲友，试图彻底取代他。亨利报警无果，反被怀疑精神有问题。他必须独自与这个看不见的敌人赛跑，在身份被完全剥夺、社会关系被彻底窃取前，揪出这个完美窃贼的真实目的。"},{id:35,title:"十五天就玩完",cover:"85.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fe0c41d994d01211debb24e84e3384a9/manifest/video.m3u8",category:"科幻",tags:["国产","电影","科幻","惊悚","悬疑","时间循环","密室"],rating:"8.8",views:14149,duration:"17:28",description:"一觉醒来，八人被困陌生别墅，被告知游戏开始，十五天内找不到出口就会死。",review:"将密室逃脱、大逃杀与科幻设定结合，创意十足。节奏紧张刺激，谜题设计巧妙。人物群像在极端环境下展现出的复杂人性，引人深思，是部成功的科幻悬疑惊悚片。",region:"国产",type:"电影",year:2024,genre:"科幻 / 惊悚 / 悬疑",relatedIds:["0034","0001","0096","0095","0036","0044"],publishDate:"2024-01-18",summary:"八个互不相识的陌生人，在不同地点昏迷后，醒来发现自己身处一栋结构复杂、完全封闭的现代别墅中。别墅的智能广播宣布：“欢迎参与‘生存优化游戏’。你们有十五天时间，在别墅内找到唯一的真实出口。时间到而未离开者，将被清除。提示散落在各处，但有些提示是致命的。游戏开始。”恐慌随之而来。他们必须一边在有限时间内探索这个充满机关、谜题和误导性线索的巨大迷宫，一边应对内部因猜忌、自私和恐惧产生的分裂与冲突。随着有人因触发“致命提示”而诡异死亡，他们意识到这不仅是一场智力游戏，更是对人性的残酷考验。出口真的存在吗？"},{id:36,title:"房客请就位",cover:"89.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/929fdb8e536c1fc43a83b32d1a838547/manifest/video.m3u8",category:"喜剧",tags:["国产","电影","喜剧","剧情","都市","合租","群像"],rating:"9.7",views:9122,duration:"13:52",description:"四位背景迥异的年轻人被迫合租，在小小的出租屋里上演都市生存悲喜剧。",review:"影片真实反映了当代都市“漂一族”的生存状态，有笑有泪。群像刻画生动立体，每个角色都有其代表性和弧光。喜剧元素来源于生活细节，温馨感人，极易引发共鸣。",region:"国产",type:"电影",year:2021,genre:"喜剧 / 剧情 / 都市",relatedIds:["0076","0067","0060","0054","0009","0072"],publishDate:"2024-01-18",summary:"在房价高企的大都市，四位年轻人因为各种原因租下了同一套老旧公寓的四间卧室。他们是：梦想成为演员却只能跑龙套的乐天派周周；被裁员后假装仍在上班的IT男吴明；来自小城、努力考研第三次的安静女孩林静；以及看似神秘、昼伏夜出的自由撰稿人阿飞。四人性格迥异，生活习惯冲突不断，闹出无数笑话。但在共享狭小空间的日子里，他们也见证了彼此的落魄、坚持、秘密与梦想。从最初的疏离防备，到后来的互帮互助，他们在这间不属于自己的房子里，建立了堪比家人的情感联结，共同面对都市生活的酸甜苦辣。"},{id:37,title:"丁丁历险记第二季",cover:"97.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fbc04ae173a0e633458658e80ee78c2a/manifest/video.m3u8",category:"动画",tags:["欧美","电影","动画","冒险","喜剧","经典改编"],rating:"9.7",views:18319,duration:"14:20",description:"丁丁与船长驾驶新飞机“雪雁号”，前往南美洲寻找失落的黄金国遗迹。",review:"完美延续了经典漫画的冒险精神与幽默风格。动画制作精良，动作场面流畅刺激。南美雨林的风光展现得瑰丽神秘，新角色和新载具的加入增添了新鲜感，是适合全家观看的精彩冒险动画电影。",region:"欧美",type:"电影",year:2023,genre:"动画 / 冒险 / 喜剧 / 家庭",relatedIds:["0085","0030","0081","0100","0027","0045"],publishDate:"2024-01-19",summary:"继上一季的冒险后，年轻记者丁丁和他的伙伴——脾气暴躁但心地善良的阿道克船长，收到了考古学家朋友从南美洲寄来的神秘包裹，里面是一块刻有古老地图的陶片碎片，指向传说中的“埃尔杜拉多”（黄金国）。与此同时，国际文物走私团伙“蝰蛇”也盯上了这份宝藏。丁丁、船长，还有小狗白雪，驾驶着船长新购入的“雪雁号”水上飞机，远渡重洋，深入亚马逊雨林。他们不仅要面对雨林中的重重险阻、破解古老的印加谜题，还要与狡猾的“蝰蛇”团伙斗智斗勇，更发现了黄金国背后隐藏的关于古代先进科技的惊人秘密。"},{id:38,title:"三个老枪手",cover:"43.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/0ba4f146b0e6ea192526706f495d460f/manifest/video.m3u8",category:"喜剧",tags:["欧美","电影","喜剧","犯罪","剧情","老年","黑色幽默"],rating:"9.1",views:17894,duration:"11:33",description:"三位退休好友养老金被黑心企业吞噬，决定联手策划一场“老年版”完美抢银行。",review:"影片将犯罪题材与老年问题、喜剧元素巧妙结合，既搞笑又心酸。三位老戏骨演技精湛，火花四",region:"欧美",type:"电影",year:2017,genre:"喜剧 / 犯罪 / 剧情",relatedIds:["0068","0075","0085","0093","0028","0098"],publishDate:"2024-01-19",summary:"乔、艾尔和威利是住在同一社区的退休好友，辛劳一生，指望养老金安度晚年。然而，他们工作的工厂被收购，新公司通过法律手段侵吞了他们的养老金。走投无路、愤怒不已的三人，在观看一部抢劫电影后，萌生了一个疯狂的念头：抢劫那家坑害他们的银行。他们利用毕生积累的技能（乔是前工程师，艾尔是前印刷工，威利是前销售）和老年身份的“隐身”优势，开始周密策划。从侦查地形、设计路线到制造工具，过程笑料百出。但真当行动日来临，面对荷枪实弹的保安和突发状况，这三个平均年龄近80岁的“老枪手”能成功吗？他们的“义举”又将在社区引起怎样的反响？"},{id:39,title:"原谅我，妈妈",cover:"53.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1e53f0e1aef7ec2fb5f30ef5d309d69c/manifest/video.m3u8",category:"家庭剧情",tags:["国产","电影","家庭","剧情","亲情","和解"],rating:"9.5",views:15551,duration:"11:44",description:"一位失忆的母亲在寻找记忆的过程中，揭开了儿子深藏多年的愧疚与秘密。",review:"影片节奏沉稳，情感细腻如涓涓细流，层层递进。失忆的设定巧妙地将悬念与情感深度绑定，每一次记忆碎片的拼凑都直击人心。母子间的表演极具张力，将东方家庭中隐忍而深厚的爱刻画得淋漓尽致，结尾的和解让人潸然泪下。",region:"国产",type:"电影",year:2021,genre:"家庭剧情 / 剧情 / 情感",relatedIds:["0056","0008","0085","0016","0057","0100"],publishDate:"2024-01-20",summary:"事业有成的设计师陈默因母亲意外失忆而回到老家，在帮助母亲恢复记忆的日常里，他发现母亲口中反复念叨的“原谅我”并非指向自己，而是指向一个他已故多年的妹妹。随着旧相册和日记的发现，陈默被迫面对自己童年时因嫉妒引发的悲剧，以及母亲多年来独自承受的悲痛与保护。最终，在母亲逐渐清晰的记忆片段里，母子二人进行了跨越时空的对话，在泪水中达成了真正的谅解与彼此救赎，陈默也学会了如何与过去和解，拥抱未来。"},{id:40,title:"我们的私密幻想",cover:"92.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1116997bf50b78f22bbfaced8975a021/manifest/video.m3u8",category:"爱情",tags:["日韩","电影","爱情","奇幻","治愈","都市"],rating:"9.2",views:9874,duration:"10:41",description:"一款能具象化内心幻想的APP，意外连接了两个孤独灵魂的私密世界。",review:"设定新颖浪漫，将现代人的孤独与对连接的渴望以奇幻形式具象化。画面唯美，两个幻想世界的视觉设计极具特色，交融过程充满诗意。情感刻画含蓄而深刻，探讨了科技时代下心灵沟通的另一种可能。",region:"日韩",type:"电影",year:2019,genre:"爱情 / 奇幻 / 剧情",relatedIds:["0027","0029","0099","0070","0068","0051"],publishDate:"2024-01-20",summary:"内向的插画师美樱和沉默的图书管理员俊浩，各自在生活中感到疏离。他们偶然下载了一款名为“私密幻想”的神秘APP，可以将脑海中的幻想场景以图像形式匿名分享。美樱幻想繁花盛开的空中庭院，俊浩则幻想深夜宁静的复古图书馆。某天，系统发生错乱，两人的幻想世界开始重叠交融，他们得以窥见彼此内心最柔软的角落。从好奇到试探，再到依赖，他们通过这个独特的通道建立联系，最终鼓起勇气在现实世界中寻找对方，让虚拟的温暖幻想照进彼此的现实生活。"},{id:41,title:"新傅少的闪婚甜妻",cover:"93.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e398cb38b257828eeedbcaa0ae2856da/manifest/video.m3u8",category:"都市爱情",tags:["国产","电影","都市","甜宠","喜剧","先婚后爱"],rating:"8.8",views:9495,duration:"15:11",description:"为应对家族逼婚，高冷总裁与美食博主签下契约婚姻，却假戏真做。",review:"经典的先婚后爱设定，但执行流畅，笑点与糖分分配得当。男女主互动自然有趣，从互怼到真香的转变过程令人信服。美食元素穿插其中，增添了生活的烟火气，整体轻松下饭，甜而不腻。",region:"国产",type:"电影",year:2023,genre:"都市爱情 / 喜剧 / 契约婚姻",relatedIds:["0052","0058","0078","0045","0094","0088"],publishDate:"2024-01-21",summary:"傅氏集团继承人傅斯年为避免商业联姻，急需一位“合约妻子”。他选中了因店铺倒闭而欠债的元气美食博主苏晓。两人签订协议，约定半年后离婚。苏晓搬进傅宅，用美食和直率性格不经意间打破傅斯年的冰冷面具，更屡次用巧思化解其商业危机。傅斯年也从最初的不耐烦，渐渐被苏晓的温暖和坚韧吸引。当合约到期，家族阻力与傅斯年前女友的归来同时出现，两人不得不审视这段始于交易的关系，最终选择遵从内心，将契约变为一生承诺。"},{id:42,title:"有目标了",cover:"39.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/77ae15566dde5cfb920bae4712a38399/manifest/video.m3u8",category:"运动励志",tags:["日韩","电影","运动","励志","青春","射箭"],rating:"8.9",views:9597,duration:"18:12",description:"迷茫的高中复读生偶然接触射箭，在瞄准靶心的过程中找到了人生方向。",review:"典型的日式青春励志片，节奏明朗，情感真挚。将射箭运动与人生目标巧妙隐喻，过程热血又不失细腻。主角的成长弧光完整，配角塑造也各有亮点，团队友情刻画动人，结局充满希望。",region:"日韩",type:"电影",year:2018,genre:"运动励志 / 剧情 / 青春",relatedIds:["0087","0039","0053","0050","0029","0038"],publishDate:"2024-01-21",summary:"连续两年高考失利的大辉对未来充满迷茫，终日浑噩。一天，他无意间走入学校的射箭部，被学姐静香拉风而专注的射箭姿态吸引。在静香的鼓励下，大辉开始学习射箭。从拉不开弓到命中靶心，他不仅掌握了技术，更在“专注、平静、瞄准目标”的射箭哲学中沉淀了心性。他与静香及部员们结下深厚友谊，共同备战全国大赛。比赛关键时刻，大辉摒除杂念，心中回想起复读时的挫败与练箭时的汗水，稳稳射出了决定胜负的一箭，也为自己射出了清晰的人生道路。"},{id:43,title:"食鲨之鳄",cover:"3.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/41cb67b47a3668efaea014219666e659/manifest/video.m3u8",category:"惊悚",tags:["欧美","电影","惊悚","冒险","怪兽","生存"],rating:"9.6",views:7892,duration:"15:01",description:"沼泽深处的生物考察队，遭遇了能吞噬大白鲨的远古变异巨鳄。",review:"怪兽电影范本，氛围营造出色，沼泽的幽闭感和未知恐惧贯穿始终。巨鳄的设计兼具科学想象与视觉冲击力。节奏紧凑，逃生戏码紧张刺激，主角的心理挣扎与成长也为单纯的逃生戏码增添了深度。",region:"欧美",type:"电影",year:2022,genre:"惊悚 / 冒险 / 怪兽",relatedIds:["0011","0017","0036","0072","0055","0010"],publishDate:"2024-01-22",summary:"一支生物学家小队深入路易斯安那州神秘沼泽，调查一系列海洋生物离奇出现在淡水区的现象。队伍中包括因事故而畏惧水域的前海军潜水员杰克。他们发现，这一切的源头是一头因基因污染而变异的史前巨鳄“黑鬣”，它不仅体型庞大，力量惊人，更拥有在海陆两种环境自如活动、捕食鲨鱼的能力。考察队的船只被毁，通讯中断，队员们被困在沼泽孤岛，成为这头顶级掠食者的猎物。杰克必须克服内心恐惧，利用环境和有限的装备，带领幸存者与这头“食鲨之鳄”展开一场绝地求生。"},{id:44,title:"缘来花开",cover:"77.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/31227358d3c181b7168e28ad248cfb4e/manifest/video.m3u8",category:"乡村爱情",tags:["国产","电影","乡村","爱情","治愈","扶贫"],rating:"9.4",views:16400,duration:"13:27",description:"失意女律师返乡散心，与坚守乡村的花木种植能手碰撞出意外情缘。",review:"影片画面清新如田园诗，将美丽乡村建设与爱情故事自然融合。男女主人设反差有趣，互动从磕绊到默契的过程真实可信。故事充满正能量，展现了现代青年返乡创业、建设家乡的情怀，温馨治愈。",region:"国产",type:"电影",year:2020,genre:"乡村爱情 / 剧情 / 治愈",relatedIds:["0064","0019","0096","0085","0056","0004"],publishDate:"2024-01-22",summary:"精英律师林薇因职业倦怠和情感挫折回到童年生活的江南花木之乡休养。她重逢了儿时玩伴、如今是花卉种植能手和电商带头人的周川。周川正致力于推广家乡花木，带动村民脱贫，却面临技术和销路瓶颈。林薇从最初的不适应，到被周川的执着与乡亲们的淳朴打动，运用自己的法律和商业知识帮助他解决合同纠纷、打造品牌。两人在共同奋斗中，感情悄然滋生。当城市的高薪职位再次召唤，林薇在漫山花海与质朴真情中，找到了人生与爱情真正绽放的方向。"},{id:45,title:"童军手册之僵尸启示录",cover:"10.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/d0af4221b8947fda8c23f4955947cb58/manifest/video.m3u8",category:"喜剧",tags:["欧美","电影","喜剧","恐怖","僵尸","童军"],rating:"9.2",views:9065,duration:"16:03",description:"三个菜鸟童子军在周末露营时，误入僵尸爆发区，用手册知识努力求生。",review:"将恐怖僵尸题材与青少年喜剧巧妙结合，创意十足。大量利用童军知识对抗僵尸的情节既滑稽又合理，充满巧思。三个小主角的表演生动有趣，血腥程度克制，整体娱乐性很强，是一部另类的青春冒险片。",region:"欧美",type:"电影",year:2015,genre:"喜剧 / 恐怖 / 冒险",relatedIds:["0009","0052","0038","0058","0057","0030"],publishDate:"2024-01-23",summary:"为了赢得最高荣誉勋章，童子军成员本、卡特和奥吉跟着不靠谱的领队来到偏远森林露营。然而当晚，附近军事基地病毒泄漏，僵尸肆虐。领队很快遇害，三个男孩被困在营地。面对成群的不死生物，他们手无寸铁，只能依靠《童军手册》里的野外生存知识急中生智：用绳索陷阱绊倒僵尸、用净水片制造“毒药”、用信号镜反射阳光干扰。在求生过程中，他们不仅运用了技能，更践行了“时刻准备着”的童军精神，从互相拆台到团结协作，最终成功发出求救信号，并意外成为了拯救小镇的英雄。"},{id:46,title:"彼岸岛 Deluxe",cover:"54.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e70b98acb53eb889d108057988609efb/manifest/video.m3u8",category:"恐怖",tags:["日韩","电影","恐怖","动作","吸血鬼","漫改"],rating:"8.8",views:7330,duration:"14:38",description:"哥哥失踪于神秘孤岛，弟弟与同伴登岛寻找，却发现岛上遍布嗜血异形。",review:"作为漫画改编电影，还原了原作中阴森诡异的氛围和奇形怪状的吸血鬼设定。动作场面密集且血腥暴力度高，充分满足了cult片爱好者的口味。剧情紧凑，主角团的绝望感与求生欲贯穿始终，恐怖压迫感十足。",region:"日韩",type:"电影",year:2016,genre:"恐怖 / 动作 / 吸血鬼",relatedIds:["0038","0015","0064","0058","0057","0021"],publishDate:"2024-01-23",summary:"宫本明的哥哥宫本笃失踪前留下信息指向名为“彼岸岛”的孤岛。明与几位朋友冒险登岛寻找，却发现岛上居民早已被名为“雅”的吸血鬼种族统治。这些“雅”并非传统吸血鬼，而是形态各异、拥有特殊能力的恐怖异形。岛上的幸存者寥寥无几，在抵抗领袖美军的帮助下，明一行人艰难求生，并得知哥哥可能已变成最强的“邪鬼”。为了拯救哥哥和同伴，明必须拿起武器，在这座绝望之岛上杀出一条血路，直面岛屿最深处的黑暗秘密与终极邪恶。"},{id:47,title:"一路向前2024",cover:"37.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/86ea18f9954dbaf22eff5e16c41b4a25/manifest/video.m3u8",category:"剧情",tags:["国产","电影","公路","家庭","剧情","治愈"],rating:"9.4",views:14975,duration:"16:50",description:"中年父亲用改造的三轮车，载着患有自闭症的儿子，踏上漫长的寻妻之路。",review:"公路片的外壳包裹着深沉的家庭情感内核。演员表演真挚动人，尤其是父子间的互动，沉默中有惊涛骇浪。影片节奏平实却有力，沿途风土人情的展现丰富了故事层次。最终的情感落点温暖而富有力量，引人深思。",region:"国产",type:"电影",year:2024,genre:"剧情 / 家庭 / 公路",relatedIds:["0067","0018","0091","0089","0059","0010"],publishDate:"2024-01-24",summary:"货车司机老陈的妻子五年前离家出走，杳无音信。他独自抚养患有自闭症的儿子小光。小光年满十八，情绪愈发不稳定，唯一能让他平静的是母亲留下的旧照片和歌谣。老陈毅然卖掉货车，改造了一辆带遮棚的三轮车，决定带着小光，按照妻子旧照片的背景，沿国道一路向南寻找。路途遥远艰辛，父子俩风餐露宿，遇到了好心人也遭遇了冷眼。在这段特殊的旅程中，沉默的小光用画笔记录所见，老陈则逐渐理解了儿子独特的内心世界，父子关系在磕绊中重建。他们寻找的终点，或许并非某个人，而是彼此的理解与接纳。"},{id:48,title:"叶卡捷琳娜大帝 第一季",cover:"16.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/2df81e778442675885257ce3e84c7173/manifest/video.m3u8",category:"历史",tags:["欧美","电影","历史","传记","宫廷","权谋"],rating:"9.3",views:6181,duration:"13:51",description:"讲述德国公主如何成为俄罗斯历史上最强有力的女皇叶卡捷琳娜二世的崛起史诗。",review:"制作精良，宫廷布景与服装华美考究。女主角的表演极具说服力，精准刻画了从隐忍到霸气的转变。剧情紧凑，权谋斗争跌宕起伏，生动再现了那段波澜壮阔的历史，是一部出色的历史人物传记片。",region:"欧美",type:"电影",year:2019,genre:"历史 / 传记 / 剧情",relatedIds:["0045","0078","0037","0097","0024","0079"],publishDate:"2024-01-24",summary:"本剧聚焦于叶卡捷琳娜二世统治早期的关键岁月。原为德意志小国公女的索菲亚，远嫁俄罗斯成为皇储彼得三世的妻子。她努力学习俄语，皈依东正教，改名叶卡捷琳娜，却遭遇丈夫的冷落与宫廷的排挤。在女皇伊丽莎白去世后，昏庸残暴的彼得三世继位，国家陷入危机。叶卡捷琳娜凭借其智慧、魅力与政治手腕，赢得了近卫军和部分贵族的支持，发动政变，废黜丈夫，加冕为女皇。影片展现了她如何巩固权力，推行启蒙思想，处理复杂的情感和政治联盟，在男性主导的世界里，一步步建立起属于自己的帝国伟业。"},{id:49,title:"危机边缘第一季",cover:"17.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/af3d3f3b4940cee04efcd8ff2c9eef0a/manifest/video.m3u8",category:"科幻",tags:["欧美","电影","科幻","悬疑","惊悚","平行世界"],rating:"8.5",views:14206,duration:"11:41",description:"FBI女探员加入秘密部门，调查一系列无法用科学解释的“边缘”案件。",review:"每集一个高概念科幻案件，想象力天马行空，悬疑感营造极佳。沃尔特博士这个角色是最大亮点，科学狂人与慈父的反差充满魅力。主线剧情层层递进，关于平行世界的设定宏大而引人入胜，为后续系列打下坚实基础。",region:"欧美",type:"电影",year:2008,genre:"科幻 / 悬疑 / 惊悚",relatedIds:["0009","0073","0095","0098","0020","0047"],publishDate:"2024-01-25",summary:"FBI新人奥莉维亚·德纳姆被招募进国土安全部下属的“危机边缘”部门，与天才但古怪的科学家沃尔特·毕舍普及其儿子彼得一起工作。他们调查一系列被称为“Pattern”的离奇事件：人体自燃、集体幻觉、基因突变等。这些事件都与毕舍普博士多年前在“边缘”科学领域（如心灵感应、平行宇宙）的禁忌实验有关。随着调查深入，奥莉维亚发现自己与这些事件有着意想不到的联系，而一个试图连接或入侵这个世界的平行宇宙的威胁逐渐浮出水面。她必须在科学与疯狂之间找到真相，防止两个世界的碰撞。"},{id:50,title:"低头诱宠",cover:"20.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/60b4ddb3d166e1239abfc7adf611a6a3/manifest/video.m3u8",category:"都市爱情",tags:["国产","电影","都市","甜宠","职场","霸总"],rating:"10.0",views:12576,duration:"17:24",description:"职场小白误将高冷总裁当成手机宠物游戏角色，进行了一系列“投喂”与“调教”。",review:"设定新颖有趣，错位感制造了源源不断的笑点和甜蜜互动。男女主反差萌十足，化学反应强烈。故事轻松欢快，完美满足了观众对“霸总”反被“套路”的甜宠幻想，是一部合格的下饭小甜饼。",region:"国产",type:"电影",year:2022,genre:"都市爱情 / 甜宠 / 职场",relatedIds:["0060","0003","0095","0070","0008","0058"],publishDate:"2024-01-25",summary:"游戏公司策划助理温妍沉迷一款名为“诱宠”的手机养成游戏，可以领养虚拟角色并进行互动。某日她无意中扫描了公司CEO陆泽洲的侧脸，游戏竟成功生成一个以他为原型的“高冷总裁”角色。温妍信以为真，每天对着“游戏角色”陆泽洲发送嘘寒问暖的消息、分享零食照片，甚至进行“摸头杀”等虚拟互动。而这一切，都通过一个漏洞同步到了陆泽洲的私人手机。从未感受过如此直白又古怪“关怀”的陆泽洲，从最初的恼怒、疑惑，到渐渐被这份单纯的“蠢萌”吸引，开始暗中观察并回应现实中的温妍，一场啼笑皆非又甜度超标的错位恋爱就此展开。"},{id:51,title:"烟火人间岁月长",cover:"33.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/a27121d514ff0079e1e81a6678f14e0c/manifest/video.m3u8",category:"剧情",tags:["国产","电影","年代","家庭","剧情","生活"],rating:"8.9",views:8415,duration:"19:47",description:"透过一家老字号餐馆的兴衰，看一个普通家庭跨越五十年的聚散离合。",review:"叙事宏大而细腻，如同一幅缓缓展开的平民生活画卷。年代感还原精准，细节处处见真情。演员表演朴实自然，将普通家庭的坚韧与温情刻画得入木三分。美食与情感的勾连做得非常好，是一部有烟火气、有温度的时代记忆之作。",region:"国产",type:"电影",year:2017,genre:"剧情 / 家庭 / 年代",relatedIds:["0058","0052","0072","0019","0038","0073"],publishDate:"2024-01-26",summary:"影片从上世纪七十年代讲起，聚焦于“兴隆菜馆”的经营者宋家。父亲宋保国手艺精湛，母亲刘秀兰勤劳持家，三个孩子性格各异。故事跟随这家餐馆，历经改革开放的机遇、九十年代的下岗潮、新世纪的拆迁改造。家庭成员们因事业、婚姻、理想而分离又重聚，菜馆也从鼎盛到面临关张，最终在第三代手中以新式私房菜馆的形式重生。五十年的光阴里，餐桌上变换的是菜肴，不变的是亲情与记忆的味道。影片通过一道道家常菜，串联起时代变迁下小人物的悲欢，展现了中国人对家庭与根的眷恋。"},{id:52,title:"逃亡者",cover:"48.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/f0d38b8679a1231eff816a8e04cc1a0c/manifest/video.m3u8",category:"动作",tags:["日韩","电影","动作","悬疑","犯罪","追逃"],rating:"9.0",views:6767,duration:"17:00",description:"被诬陷为杀害妻子的凶手，前国际刑警踏上跨国逃亡与追凶之路。",review:"动作场面设计精彩，跨国取景丰富了视觉体验。悬疑铺设层层递进，反转出人意料。男主角在逃亡过程中的孤勇与智谋令人印象深刻，与女主角亦敌亦友的关系张力十足。整体节奏快而不乱，是一部制作精良的商业动作片。",region:"日韩",type:"电影",year:2010,genre:"动作 / 悬疑 / 犯罪",relatedIds:["0096","0011","0006","0066","0085","0073"],publishDate:"2024-01-26",summary:"前国际刑警金智宇在婚礼当天，目睹未婚妻被神秘杀手枪杀，自己却被警方认定为凶手。为找出真凶，洗刷冤屈，智宇不得不开始逃亡。他利用自己的专业技能，躲避警方和国际刑警的追捕，同时根据零星线索，从韩国追查到日本、泰国，乃至澳门。在逃亡途中，他结识了身份成谜的女人真希，两人时而合作时而猜疑。随着调查深入，一个涉及巨额国际黑金和政治阴谋的庞大网络逐渐显现，而真凶的身份和他与智宇之间千丝万缕的联系，更是出乎所有人的意料。"},{id:53,title:"团宠之蒋家小女会仙法",cover:"14.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c66b5309b3b64d15ed856810d6cc0b72/manifest/video.m3u8",category:"古装",tags:["国产","电影","古装","奇幻","喜剧","团宠"],rating:"9.9",views:11862,duration:"13:13",description:"修仙界天才少女渡劫失败，穿成侯府体弱多病的庶女，被全家当成宝贝宠上天。",review:"将穿越修仙与古装宅斗甜宠巧妙结合，设定有趣。家庭互动温馨搞笑，“团宠”氛围营造得十足。女主扮猪吃老虎的桥段爽感适度，整体风格轻松欢快，是解压放松的佳作。",region:"国产",type:"电影",year:2023,genre:"古装 / 奇幻 / 家庭喜剧",relatedIds:["0015","0093","0068","0083","0085","0014"],publishDate:"2024-01-27",summary:"修仙界天之骄女凌霜仙子渡劫时遭暗算，神魂穿越到架空古代，成为安定侯府体弱多病、备受冷落的庶女蒋暖心。本想低调恢复修为，却发现这一世的家人与想象中不同。严肃的侯爷爹其实是个女儿奴，端庄的主母娘偷偷给她塞零花钱，几位兄长更是争相护短。暖心偶尔展露的“仙法”（如用灵力催生花朵、隔空取物）被家人误以为是福运或小把戏，更加爱若珍宝。她用仙法暗中解决家族危机，调理家人身体，不知不觉成为全府乃至全京城的“团宠”。直到原主的仇敌和修仙界的追踪者陆续出现，暖心不得不为了守护这个温暖的家而真正出手。"},{id:54,title:"小好、小麻、佐和子",cover:"68.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c99d86ece73a935b77e57d322461ddb5/manifest/video.m3u8",category:"剧情",tags:["日韩","电影","女性","剧情","生活","友谊"],rating:"9.8",views:12987,duration:"13:30",description:"三位性格迥异的三十岁女性，在平淡日常中分享彼此的生活、烦恼与微小幸福。",review:"典型的日式生活流电影，叙事舒缓如散文，对女性心理的刻画精准而入微。三位女主演技自然，友谊的呈现真实可信。影片充满了生活细节的观察，平淡中见真章，能引起广泛共鸣，温暖而治愈。",region:"日韩",type:"电影",year:2013,genre:"剧情 / 女性 / 生活",relatedIds:["0085","0067","0062","0039","0025","0088"],publishDate:"2024-01-27",summary:"小好是认真却有些怯懦的办公室职员，暗恋公司前辈却不敢表白；小麻性格洒脱，从事自由职业，对婚姻抱有疑虑；佐和子温和顾家，正准备与男友结婚。三人是自学生时代起的好友，定期聚会，在咖啡馆、居酒屋或彼此的公寓里，分享工作中的委屈、感情上的困惑、对未来的迷茫。没有剧烈的戏剧冲突，只有细腻的生活流：小好鼓起勇气的告白尝试，小麻面对母亲催婚的压力，佐和子婚前对自我价值的思考。影片跟随她们的脚步，展现现代都市单身女性在友情支撑下，如何面对人生的十字路口，寻找属于自己的“小确幸”与前进方向。"},{id:55,title:"重生让老婆当上诰命夫人",cover:"45.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fe0c41d994d01211debb24e84e3384a9/manifest/video.m3u8",category:"古装",tags:["国产","电影","古装","重生","甜宠","权谋"],rating:"9.4",views:18332,duration:"11:13",description:"负心汉重生回落魄时，决心弥补前世亏欠，助贤妻一步步获封诰命。",review:"男主重生追妻火葬场的设定抓人，悔过与弥补的过程满足情感需求。女主并非单纯等待拯救，有自己的事业和闪光点。权谋部分简练不儿戏，感情线真挚动人，整体是一部完成度很高的古言重生甜宠片。",region:"国产",type:"电影",year:2024,genre:"古装 / 爱情 / 穿越重生",relatedIds:["0013","0049","0057","0019","0066","0036"],publishDate:"2024-01-28",summary:"寒门书生沈煜高中状元后抛妻弃子，攀附权贵，最终却身败名裂，孤独终老。弥留之际，他得知原配妻子林晚在他离开后艰辛抚育子女，受尽苦楚。再睁眼，沈煜重生回进京赶考前，家徒四壁，妻子正熬夜为他缝补衣衫。悔恨交加的沈煜决心彻底改变。他凭借前世记忆规避风险，巧妙应对科场与官场风波，更一心一意对待林晚，尊重她的想法，支持她行医济世的善举。在他的努力与妻子的善良影响下，沈煜官途顺畅，更因功绩为林晚请封。最终，林晚凭借自己的医术和德行，获封诰命夫人，夫妻二人成就了一段佳话。"},{id:56,title:"触不到的恋人2000",cover:"98.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/929fdb8e536c1fc43a83b32d1a838547/manifest/video.m3u8",category:"爱情",tags:["日韩","电影","爱情","奇幻","穿越","悲伤"],rating:"9.2",views:19196,duration:"18:19",description:"通过海边神秘信箱，生活在不同时间的男女展开了一场跨越时空的通信与恋爱。",review:"影片氛围唯美而忧伤，充满了诗意和宿命感。时空交错的设定被运用得巧妙而克制，情感积累层层递进。全智贤和李政宰的表演细腻动人，将那种无法触及的思念演绎得淋漓尽致。结局的转折令人心碎又回味无穷，是经典爱情电影。",region:"日韩",type:"电影",year:2e3,genre:"爱情 / 奇幻 / 剧情",relatedIds:["0045","0068","0004","0014","0026","0043"],publishDate:"2024-01-28",summary:"1999年的建筑师韩星贤搬入海边小屋“Il Mare”，发现一个来自未来的神秘女子金恩澍留下的信件，她生活在2000年。通过这个伫立在海边的信箱，两人开始了跨越一年的书信往来，分享彼此的生活、烦恼和情感。他们逐渐相爱，却无法触碰对方，只能通过信件和留在信箱里的物品互动。星贤得知恩澍的男友已故，而悲剧似乎与一场意外有关。为了改变历史，拯救恩澍的爱人，星贤在1999年做出了一个大胆的决定，而这个决定，也彻底改变了他们两人命运的轨迹，带来一个既悲伤又充满希望的结局。"},{id:57,title:"常春藤",cover:"86.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fbc04ae173a0e633458658e80ee78c2a/manifest/video.m3u8",category:"剧情",tags:["欧美","电影","剧情","家庭","成长","教育"],rating:"9.4",views:7791,duration:"17:02",description:"一位非传统教育背景的母亲，为让女儿进入顶尖藤校，不惜挑战整个精英教育体系。",review:"选题贴近现实，具有强烈的社会讨论价值。母女关系刻画深刻，既是战友又难免冲突。影片对精英教育体系的批判尖锐但不流于表面，结局的处理发人深省。演员表演扎实，情感真挚有力。",region:"欧美",type:"电影",year:2021,genre:"剧情 / 家庭 / 成长",relatedIds:["0082","0093","0049","0085","0095","0003"],publishDate:"2024-01-29",summary:"单身母亲伊芙琳自学成才，以非主流的方式教育女儿莉莉，培养了她的批判思维和创造力，但莉莉缺乏标准化成绩和课外活动清单。当莉莉展现出进入顶尖“常春藤”大学的惊人潜力时，伊芙琳决定尝试。她们面对的是僵化的申请系统、势利的升学顾问和充满偏见的社会。伊芙琳用她独特的方式为莉莉准备申请，强调真实经历而非包装，却屡遭挫败。最终，在一位良心发现的教授帮助下，莉莉的真实才华得以在面试中绽放。影片不仅关于升学，更深刻探讨了教育的本质、阶级壁垒与何为真正的成功。"},{id:58,title:"滴血黄昏",cover:"36.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/0ba4f146b0e6ea192526706f495d460f/manifest/video.m3u8",category:"动作",tags:["国产","电影","动作","犯罪","悬疑","警匪"],rating:"8.6",views:16553,duration:"13:21",description:"老刑警在退休前最后一案中，追捕一个专在黄昏作案的连环杀手。",review:"充满硬核气质的警匪片，氛围营造阴郁而紧迫。老刑警的形象立体丰满，其偏执与责任感令人动容。追凶过程逻辑缜密，动作场面写实激烈。结局充满悲壮色彩，是对一个时代刑警的致敬。",region:"国产",type:"电影",year:2005,genre:"动作 / 犯罪 / 悬疑",relatedIds:["0066","0072","0065","0047","0049","0046"],publishDate:"2024-01-29",summary:"刑警队长老马还有三天退休，却接到一桩凶案：受害者被以特定仪式杀害，作案时间均在黄昏。这让他联想到二十年前一桩未破的悬案。局里将案件交给年轻干探负责，但老马凭借经验和直觉，坚持独自调查。他发现所有受害者都与一宗陈年旧怨有关，而杀手的目标名单尚未完结。在追踪过程中，老马与杀手在城市的角落展开猫鼠游戏，数次擦肩而过。最终，在老马曾经失误导致战友牺牲的旧码头，在又一个滴血的黄昏，他与真凶面对面。这不仅是对凶手的追捕，也是老马对自己职业生涯和心结的一次彻底清算。"},{id:59,title:"想被女子高中生杀掉",cover:"46.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1e53f0e1aef7ec2fb5f30ef5d309d69c/manifest/video.m3u8",category:"剧情",tags:["日韩","电影","剧情","心理","剧情","黑色"],rating:"9.0",views:18071,duration:"10:40",description:"对生活绝望的中年男子，唯一的心愿是能被一名女高中生杀死。",review:"题材极其大胆另类，深入探讨了存在主义危机与社会的疏离感。叙事冷静克制，将黑色幽默与深沉悲悯融合。男主角的表演堪称精湛，将角色的绝望、扭曲与残存的人性挣扎刻画得入木三分，是一部令人深感震撼和不适的佳作。",region:"日韩",type:"电影",year:2021,genre:"剧情 / 心理 / 剧情",relatedIds:["0045","0078","0005","0071","0032","0017"],publishDate:"2024-01-30",summary:"碌碌无为、孤独厌世的保险公司职员佐藤，某天产生了“想被女子高中生杀掉”的荒谬念头。他认为这是自己毫无价值的人生能留下的最后印记。他开始在网络上寻找潜在的对象，并遇到了形形色色的少女：有遭受霸凌的、有家庭破碎的、有对世界充满愤怒的。佐藤试图接近并“引导”她们杀死自己，却在与这些少女的接触中，意外窥见了她们各自深藏的伤痛与困境。这个扭曲的“寻死”过程，反而演变成对他人痛苦的见证。最终，在试图“帮助”一名少女解脱时，佐藤做出了完全相反的选择，他的“求死”愿望以意想不到的方式落空，却也找到了某种畸形的救赎。"},{id:60,title:"2023年KBS演艺大赏",cover:"9.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1116997bf50b78f22bbfaced8975a021/manifest/video.m3u8",category:"喜剧",tags:["日韩","电影","喜剧","伪纪录片","讽刺","娱乐圈"],rating:"9.2",views:18795,duration:"10:22",description:"一部伪纪录片，跟踪拍摄某电视台演艺大赏幕后荒诞无比的筹备与颁奖过程。",review:"形式新颖，伪纪录片的手法增强了真实感和讽刺力度。台词和情节设计充满巧思，对娱乐圈各种乱象的调侃入木三分又令人捧腹。演员表演自然，仿佛本色出演。是一部兼具娱乐性和批判性的聪明之作。",region:"日韩",type:"电影",year:2023,genre:"喜剧 / 伪纪录片 / 讽刺",relatedIds:["0040","0041","0088","0009","0032","0094"],publishDate:"2024-01-30",summary:"影片以伪纪录片形式，辛辣讽刺娱乐圈颁奖礼。导演组获得“独家许可”，全程跟拍KBS电视台“2023演艺大赏”从策划到落幕的全过程。镜头揭示了不为人知的幕后：评委们的随意投票、经纪公司间的资源博弈、艺人为了奖项的明争暗斗、PD为了收视率绞尽脑汁设计噱头、颁奖嘉宾的尴尬口误、获奖者的“惊喜”表演。通过一连串荒谬又真实的细节，呈现出一个光鲜舞台背后的滑稽与虚伪。最终，这场万众瞩目的颁奖礼在混乱、意外和皆大欢喜的表象中落下帷幕，留给观众无尽的玩味与思考。"},{id:61,title:"厨神小姐",cover:"26.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e398cb38b257828eeedbcaa0ae2856da/manifest/video.m3u8",category:"美食",tags:["国产","电影","美食","励志","剧情","女性"],rating:"8.8",views:10022,duration:"15:04",description:"天才女厨师为继承父亲小店，毅然挑战以男性为主导的顶尖美食大赛。",review:"美食镜头拍得令人垂涎欲滴，每道菜都有故事和巧思。女主角的成长线清晰，对抗偏见的主题具有现实意义。比赛过程跌宕起伏，最后的获胜方式既出乎意料又在情理之中，情感饱满，是一部色香味俱全的励志佳作。",region:"国产",type:"电影",year:2022,genre:"美食 / 励志 / 剧情",relatedIds:["0011","0034","0085","0002","0078","0038"],publishDate:"2024-01-31",summary:"林夏在父亲经营的传统面馆长大，厨艺天赋极高。父亲病重，面馆面临被收购。此时，权威的“金厨帽”大赛开启，冠军不仅能获得巨额奖金，还能得到顶级餐厅投资。然而，该大赛历史上从未有女性冠军。为保住父亲心血，林夏决心参赛。她将家传手艺与现代创意结合，创作出一道道惊艳菜肴，却屡遭男性评委的偏见与竞争对手的刁难。在好友和一位神秘美食评论家的帮助下，林夏顶住压力，一路过关斩将。决赛中，她用一碗融汇了记忆与情感的家常汤面，征服了所有评委的味蕾与心，证明了美味无关性别，只关乎热爱与真诚。"},{id:62,title:"爱情发生在三天后",cover:"47.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/77ae15566dde5cfb920bae4712a38399/manifest/video.m3u8",category:"爱情",tags:["日韩","电影","爱情","科幻","时间循环","治愈"],rating:"9.2",views:18883,duration:"17:53",description:"男女主被困在初次相遇的三天里循环，必须在无限轮回中确认彼此的心意。",review:"在时间循环的经典框架下，专注于爱情关系的细腻建构，设定巧妙。男女主在循环中的互动从生疏到熟稔，情感变化层次丰富。结局的设定浪漫而暖心，强调了爱与联结的力量，是一部清新脱俗的软科幻爱情片。",region:"日韩",type:"电影",year:2024,genre:"爱情 / 科幻 / 剧情",relatedIds:["0052","0034","0059","0031","0017","0064"],publishDate:"2024-01-31",summary:"内向的图书管理员秀雅和阳光的咖啡师载沅在雨天的公交站邂逅，互有好感，约定三天后再见。然而，秀雅却在次日遭遇车祸。当她醒来，发现自己回到了与载沅相遇的那天早晨。此后，她不断在这三天里循环，无论如何尝试改变，都会在第三天夜晚“重置”。在无数次循环中，秀雅从慌乱到利用循环去了解载沅，甚至拯救他于一些微小危难，两人感情急速升温。但她始终无法打破循环。直到某次循环，她发现载沅似乎也保有部分记忆。原来，这循环并非意外，而是一场关于“足够深刻的爱能否超越时间”的考验。"},{id:63,title:"盛夏晚晴天",cover:"78.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/41cb67b47a3668efaea014219666e659/manifest/video.m3u8",category:"爱情",tags:["国产","电影","爱情","青春","校园","成长"],rating:"9.6",views:19787,duration:"16:13",description:"高考结束的盛夏，两个因误会疏远的青梅竹马，在旅行中重拾旧日情愫。",review:"影片充满了夏日特有的清新、热烈与淡淡忧伤，画面唯美。青梅竹马破冰重归于好的过程自然流畅，情感细腻真实。演员青春气息十足，很好地捕捉了高考后那种既放松又迷茫的微妙心态。是一部合格的青春爱情小品。",region:"国产",type:"电影",year:2018,genre:"爱情 / 青春 / 剧情",relatedIds:["0067","0032","0068","0072","0053","0013"],publishDate:"2024-02-01",summary:"夏晴和陆晚是邻居兼青梅竹马，却因高二时一场误会导致冷战，直至高考结束也未和解。填报志愿后，两人阴差阳错参加了同一个毕业旅行团，前往海边小镇。被迫同行的尴尬在旅途中慢慢消解，在熟悉的拌嘴和共同的回忆里，当年的误会逐渐澄清。他们一起看盛夏的烟花、深夜的海、凌晨的日出，分享了关于未来与梦想的迷茫。旅程将尽，面对即将奔赴不同城市的现实，那份被压抑已久的感情终于破土而出。在最后一个晚晴天里，他们做出了关于青春与爱情的选择，为这个盛夏画下未完成的句点。"},{id:64,title:"深情不敌久伴",cover:"99.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/31227358d3c181b7168e28ad248cfb4e/manifest/video.m3u8",category:"都市情感",tags:["国产","电影","爱情","家庭","现实","治愈"],rating:"8.7",views:6694,duration:"13:44",description:"一对金婚老人在阿尔茨海默症的迷雾中，用余生证明陪伴是最长情的告白。",review:"影片节奏平实而克制，没有刻意煽情，却在日常细节中积累出巨大的情感力量。两位老戏骨的表演细腻动人，将相濡以沫的情感刻画得入木三分，让观众在泪水中体会到“久伴”二字的千钧之重。",region:"国产",type:"电影",year:2019,genre:"都市情感 / 家庭剧情",relatedIds:["0007","0049","0090","0046","0089","0054"],publishDate:"2024-02-01",summary:"退休教师林建国与妻子文秀相伴五十载，生活平静如水。然而，文秀被确诊为阿尔茨海默症，记忆逐渐褪色，甚至开始认不出相伴一生的丈夫。林建国没有放弃，他辞去返聘工作，全心照顾妻子。他用旧照片、老歌和重游故地的方式，试图唤醒妻子的记忆。过程中，子女们的不解与家庭矛盾也随之浮现。当文秀在某个清醒的片刻，抚摸着丈夫布满皱纹的脸叫出“建国”时，一切坚守都有了意义。影片讲述的不仅是疾病带来的痛苦，更是在时间与遗忘的洪流中，那份依靠日复一日陪伴积淀下来的、无法被抹去的深情。"},{id:65,title:"薇薇一笑很倾城",cover:"55.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/d0af4221b8947fda8c23f4955947cb58/manifest/video.m3u8",category:"校园青春",tags:["国产","电影","校园","甜宠","高颜值","改编"],rating:"8.6",views:8808,duration:"15:33",description:"计算机系冰山大神肖奈，对游戏里结缘的系花贝微微一见倾心，线上线下双重追爱。",review:"轻松甜宠的基调下，融合了网游元素，设定新颖有趣。男女主角颜值与演技在线，互动甜蜜自然，完美还原了小说中“微微一笑很倾城”的浪漫氛围，是经典的校园爱情童话。",region:"国产",type:"电影",year:2016,genre:"校园青春 / 浪漫爱情",relatedIds:["0028","0008","0098","0045","0093","0048"],publishDate:"2024-02-02",summary:"贝微微是A大计算机系系花，同时也是网游《梦游江湖》中的高手“芦苇微微”。她因不愿在游戏中“结婚”而遭前夫抛弃，却意外被游戏第一高手“一笑奈何”求婚。现实中的“一笑奈何”竟是同校风云人物、计算机系大神肖奈。两人从游戏搭档发展为现实情侣，但随之而来的是旁人的质疑、前游戏伴侣的挑拨以及现实中的竞争压力。肖奈的创业公司遭遇危机，贝微微则用自己出色的编程能力暗中相助。最终，两人不仅携手渡过难关，更让所有人看到，最好的爱情是并肩而立，共同成长。"},{id:66,title:"天选反骨仔",cover:"57.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e70b98acb53eb889d108057988609efb/manifest/video.m3u8",category:"奇幻动作",tags:["日韩","电影","奇幻","动作","反英雄","喜剧"],rating:"9.4",views:7147,duration:"13:59",description:"被预言注定背叛世界的“反骨仔”，决定先下手为强，把预言之神揍到改口。",review:"反套路设定令人捧腹，将经典奇幻叙事彻底颠覆。主角的“反骨”精神充满反抗命运的现代感，动作场面华丽搞笑，情感内核关于自我定义与打破宿命，畅快又热血。",region:"日韩",type:"电影",year:2023,genre:"奇幻动作 / 黑色喜剧",relatedIds:["0033","0099","0045","0021","0013","0078"],publishDate:"2024-02-02",summary:"在一个英雄与魔王并存的世界里，底层小混混金哲秀某天被“预言之神”钦定为“天选反骨仔”，预言他将背叛挚友、害死英雄、导致世界毁灭。消息传出，他瞬间从无名小卒变成全民公敌，遭到英雄阵营追杀和魔王势力的利用。不堪其扰的金哲秀怒火中烧，决定“既然都说我要造反，那我就反给你们看”！但他的目标不是世界，而是那个信口开河的神明。他集结了一群同样被命运捉弄的“倒霉蛋”，包括总打不中人的弓箭手、魔力暴走的见习魔女，踏上了一条“逆天改命”、暴揍神明的不归路。"},{id:67,title:"无名女尸",cover:"6.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/86ea18f9954dbaf22eff5e16c41b4a25/manifest/video.m3u8",category:"恐怖悬疑",tags:["欧美","电影","恐怖","悬疑","法医","超自然","密闭空间"],rating:"9.0",views:10970,duration:"13:02",description:"一具保存完好却内脏焦黑的无名女尸，让验尸官父子在密闭验尸间遭遇超自然恐怖。",review:"场景高度集中于验尸房，营造出极强的窒息感和压迫感。恐怖感主要来源于科学解剖与超自然现象的矛盾对冲，逻辑严谨，悬念层层递进，结局的留白更是细思恐极。",region:"欧美",type:"电影",year:2016,genre:"恐怖悬疑 / 法医惊悚",relatedIds:["0100","0094","0054","0016","0044","0047"],publishDate:"2024-02-03",summary:"暴风雨夜，小镇警长送来一具身份不明的年轻女尸。她体表完好无损，美丽绝伦，但内脏和骨骼却呈现出严重烧伤和断裂的痕迹。经验丰富的验尸官汤米和他的儿子奥斯汀在密闭的地下验尸房开始解剖。随着解剖深入，超自然现象接连发生：收音机自动切换频道，尸体似乎能影响他们的心智，展现他们内心的恐惧。他们发现女尸体内的伤痕并非外力造成，而是源自某种古老的巫术诅咒。父子俩必须赶在被女尸的怨念彻底吞噬前，揭开她死亡的真相，但每接近真相一步，死亡威胁就更近一分。"},{id:68,title:"恶梦1979",cover:"65.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/2df81e778442675885257ce3e84c7173/manifest/video.m3u8",category:"心理惊悚",tags:["欧美","电影","惊悚","心理","年代","家庭创伤"],rating:"8.8",views:6563,duration:"15:25",description:"1979年夏天，一个男孩深信每晚的噩梦正在现实中逐一实现，并指向家族的黑暗秘密。",review:"影片完美复刻了70年代末的美学风格，氛围营造极佳，将孩童的恐惧视角与家庭秘密结合，心理惊悚感步步紧逼。结局的揭示不仅关乎超自然，更深挖了家庭记忆与愧疚的沉重主题。",region:"欧美",type:"电影",year:2018,genre:"心理惊悚 / 年代剧情",relatedIds:["0045","0025","0004","0079","0014","0070"],publishDate:"2024-02-03",summary:"1979年盛夏，11岁的比利随家人搬到宁静的郊区小镇。从搬进老房子的第一夜起，他就开始做重复的噩梦：一个看不清面容的女人在走廊尽头哭泣，地下室里传来持续不断的抓挠声。起初父母认为只是孩子适应新环境的不安，但比利惊恐地发现，梦中的细节开始出现在现实——墙上的污渍形状、阁楼找到的旧娃娃。他试图向家人预警，却只被当作胡思乱想。当比利的妹妹也开始出现梦游并重复噩梦中的话语时，他不得不独自调查这所房子和家族的历史，逐渐触及父母一直试图掩盖的一桩发生在数年前的悲剧。"},{id:69,title:"塬上春来早",cover:"59.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/af3d3f3b4940cee04efcd8ff2c9eef0a/manifest/video.m3u8",category:"乡村剧情",tags:["国产","电影","乡村","家庭","脱贫","人文"],rating:"9.2",views:7348,duration:"12:29",description:"黄土高原上的老支书，在生命最后一年，誓要为干旱的村庄引来春天的第一股活水。",review:"影片扎根中国乡土，情感真挚厚重。主角形象朴实而伟大，演员表演极具感染力。故事将个人生命倒计时与集体福祉相结合，展现了普通人如黄土般深沉坚韧的精神力量，感人至深。",region:"国产",type:"电影",year:2021,genre:"乡村剧情 / 家庭剧情",relatedIds:["0042","0051","0072","0018","0085","0014"],publishDate:"2024-02-04",summary:"在十年九旱的黄土高原，老支书赵满仓被诊断出肺癌晚期，医生说他最多还有一年。他没有告诉村民，而是默默许下最后一个心愿：在明年春天到来前，为村子解决困扰几代人的吃水问题。面对资金短缺、技术难关和部分村民的质疑，赵满仓拖着病体，一次次往返于县里和山村，争取项目，学习新技术。他的儿子从城里回来，试图接他去治疗，却最终被父亲的执着和村民的期盼打动，留下来一起奋斗。开春那天，当清澈的泉水通过新建的管道流入干涸的村庄，赵满仓在众人的欢呼声中安然闭上了眼睛，他带来的“春天”，终于早早地眷顾了这片土地。"},{id:70,title:"自古英雄多寂寞",cover:"35.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/60b4ddb3d166e1239abfc7adf611a6a3/manifest/video.m3u8",category:"武侠剧情",tags:["国产","电影","武侠","历史","英雄","悲情"],rating:"9.3",views:8951,duration:"12:37",description:"一代剑圣独孤鸿退隐江湖，却为守护一个承诺，重拾长剑，直面昔日兄弟与天下为敌。",review:"电影充满古典武侠的苍凉意境，打斗设计飘逸而富有哲理。着力刻画英雄光环背后的牺牲与寂寞，人物塑造丰满，在刀光剑影中探讨了道义、承诺与孤独的永恒命题。",region:"国产",type:"电影",year:2008,genre:"武侠剧情 / 历史传奇",relatedIds:["0065","0016","0044","0095","0041","0011"],publishDate:"2024-02-04",summary:"明朝末年，剑圣独孤鸿因厌倦江湖纷争，于天山之巅归隐，只与一只白猿为伴。十年后，故人之女林雪儿携其父遗书与半块玉佩寻来，求他保护一本关乎天下气运的《山河秘典》。追杀者随即而至，竟是独孤鸿当年的结义兄弟、如今权倾朝野的东厂督主曹少钦。为履行对故友的承诺，独孤鸿不得不重入红尘。他带着雪儿一路逃亡，沿途目睹民不聊生，昔日侠义道好友或避世或变节。在最终对决中，他不仅要战胜武功已臻化境的曹少钦，更要面对信念的崩塌与英雄道路上的亘古孤独。"},{id:71,title:"佳许末至",cover:"87.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/a27121d514ff0079e1e81a6678f14e0c/manifest/video.m3u8",category:"纯爱文艺",tags:["日韩","电影","爱情","文艺","绝症","治愈"],rating:"9.1",views:18835,duration:"16:34",description:"生命仅剩三个月的女孩，与梦想破灭的男孩相遇，共同书写一份“未来”的愿望清单。",review:"影片叙事清新细腻，画面唯美，将悲伤的故事拍出了温暖的质感。两位主角的互动自然动人，没有过度煽情，却在平淡日常中积蓄了强大的情感力量，关于生命与爱的主题深刻而治愈。",region:"日韩",type:"电影",year:2014,genre:"纯爱文艺 / 生命感悟",relatedIds:["0076","0011","0043","0057","0017","0046"],publishDate:"2024-02-05",summary:"患有先天心脏病的少女佳许，被告知生命可能只剩下最后三个月。她一直乖巧地待在医院，从未真正体验过外面的世界。与此同时，怀揣摄影梦想的青年末至，因一次意外导致手部受伤，可能再也无法拿起相机，陷入绝望。二人在医院天台相遇。佳许拿出自己列下的“生命愿望清单”，请求末至帮助她完成。末至起初冷淡，却被佳许对生命纯粹的热忱打动。他们一起去看海、放烟花、在夜市吃小吃……末至用手机记录下这一切。在帮助佳许实现愿望的过程中，末至也重新找到了生活的意义和摄影的新可能。当春天来临，佳许安静离开，末至举办了一场摄影展，名字就叫“佳许末至”。"},{id:72,title:"德云社张鹤伦郎鹤炎相声专场武汉站2022",cover:"21.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/f0d38b8679a1231eff816a8e04cc1a0c/manifest/video.m3u8",category:"喜剧",tags:["国产","电影","相声","纪实","喜剧","专场"],rating:"9.0",views:11755,duration:"15:34",description:"记录德云社“小白大黄”组合2022年武汉相声专台的台前幕后与观众的热烈互动。",review:"这是一部给相声粉丝的深情礼物，也是观察当代曲艺演出的生动窗口。影片剪辑节奏明快，现场感极强，既保留了相声的完整趣味，又揭示了舞台下的汗水与真诚，笑点与温情并存。",region:"国产",type:"电影",year:2023,genre:"喜剧 / 纪录片",relatedIds:["0070","0064","0011","0033","0027","0085"],publishDate:"2024-02-05",summary:"本片以纪实手法，全程记录了德云社知名相声演员张鹤伦、郎鹤炎2022年在武汉举行相声专场的完整过程。影片不仅捕捉了《童年趣事》、《我为歌狂》等经典段子在现场引爆的笑料与高潮，更将镜头延伸至后台，展现二人对活、备场、与工作人员沟通的细节，以及上场前片刻的紧张与期待。同时，影片穿插了对不同年龄层、不同职业武汉观众的采访，聆听他们与相声的故事，以及这场演出在特殊时期后带来的欢乐与慰藉。电影最终在《小娟》的合唱中达到情感顶点，呈现了传统曲艺连接人与人、传递快乐的独特魅力。"},{id:73,title:"谎言的代价",cover:"63.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c66b5309b3b64d15ed856810d6cc0b72/manifest/video.m3u8",category:"悬疑剧情",tags:["欧美","电影","悬疑","剧情","家庭","剧情","心理"],rating:"9.6",views:19872,duration:"14:48",description:"一次为保护女儿而说的谎，如多米诺骨牌般连锁反应，最终摧毁了整个家庭。",review:"影片叙事冷静克制，层层递进地展现了“一个谎言引发无数谎言”的可怕过程。剧本扎实，对人性在压力下的脆弱与自私刻画入微，结局震撼而引人深思，是关于道德抉择的现代寓言。",region:"欧美",type:"电影",year:2022,genre:"悬疑剧情 / 家庭剧情",relatedIds:["0048","0009","0083","0031","0012","0085"],publishDate:"2024-02-06",summary:"成功的律师大卫和妻子艾玛拥有令人羡慕的家庭。一天，他们17岁的女儿莉莉在派对后卷入了一场致命车祸，同车男孩身亡。为保护女儿前途，大卫利用专业知识，教莉莉编织了一个完美的谎言，并将现场伪装成意外。起初一切顺利，但随着警方调查深入，谎言需要更多谎言来弥补。夫妻之间出现信任裂痕，莉莉承受着巨大的心理煎熬。原本的受害者家庭锲而不舍地追寻真相，而大卫事业上的对手也嗅到了机会。当所有谎言编织的脆弱网络即将崩断时，这个家庭面临的不仅是法律制裁，更是亲情与良知上的彻底破产。"},{id:74,title:"我家小姐来自一千年前",cover:"100.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c99d86ece73a935b77e57d322461ddb5/manifest/video.m3u8",category:"古装穿越",tags:["国产","电影","穿越","喜剧","爱情","古风"],rating:"9.6",views:15221,duration:"16:48",description:"考古系宅男挖出一位沉睡千年的唐朝郡主，被迫开始一场鸡飞狗跳的古今同居生活。",review:"穿越题材的清新之作，古今文化碰撞的笑点密集且自然。女主“古人”设定带来的反差萌十足，男主从崩溃到接纳的情感转变流畅。故事轻松欢脱之余，也探讨了文化归属与情感联结。",region:"国产",type:"电影",year:2023,genre:"古装穿越 / 浪漫喜剧",relatedIds:["0083","0014","0091","0032","0095","0097"],publishDate:"2024-02-06",summary:"考古专业研究生沈默，在一次田野发掘中，意外唤醒了一具沉睡千年的“活尸”——唐朝永乐郡主李长歌。长歌郡主将沈默认作自己的“护卫”，并要求他助自己寻找失散的兄长，重返大唐。无奈之下，沈默只好将这位举止古怪、观念陈旧的“大小姐”藏匿家中。从此，他的生活天翻地覆：郡主用他的电脑屏幕当铜镜，把微波炉当成妖物，试图用唐律管理小区邻居……在笑料百出的磨合中，沈默帮长歌适应现代生活，并利用历史知识查找她兄长下落。而长歌也以其独特的古代智慧，几次帮沈默化解危机。当回归唐代的线索终于出现，两人却发觉彼此已难舍难分。"},{id:75,title:"灵魂梦飞翔",cover:"1.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fe0c41d994d01211debb24e84e3384a9/manifest/video.m3u8",category:"奇幻冒险",tags:["欧美","电影","动画","奇幻","音乐","冒险","心灵"],rating:"9.7",views:10339,duration:"11:25",description:"一个梦想成为爵士乐手的中学老师，在“生之来处”遇见厌世小灵魂，共同寻找生命火花。",review:"皮克斯式的深度与想象力之作，将哲学命题包裹在绚丽多彩的视觉奇观和动人的爵士乐中。故事探讨生命意义、梦想与平凡生活的价值，情感真挚饱满，结局温暖而富有启迪性。",region:"欧美",type:"电影",year:2020,genre:"奇幻冒险 / 音乐动画",relatedIds:["0069","0042","0022","0062","0095","0019"],publishDate:"2024-02-07",summary:"乔伊·高纳是一名不得志的中学音乐老师，终于获得梦寐以求的爵士乐演出机会，却因意外跌落井盖，灵魂来到了奇妙的“生之来处”。这里，所有新生灵魂都需要找到属于自己的“火花”，才能获得地球通行证。乔伊被误认为心灵导师，指派给一个编号“22”、极度厌恶地球生活的千年老灵魂。22看遍了伟人传记，却对任何事物都提不起兴趣。一心想回到地球身体的乔伊，与顽固的22展开了一场横跨抽象思维与记忆空间的冒险，试图帮22找到火花。在这个过程中，乔伊重新审视了自己“平庸”的一生，而22则第一次感受到了生活的美好滋味。"},{id:76,title:"前说！",cover:"76.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/929fdb8e536c1fc43a83b32d1a838547/manifest/video.m3u8",category:"青春励志",tags:["日韩","电影","青春","励志","喜剧","漫才"],rating:"8.9",views:17389,duration:"15:33",description:"四个高中女生组成了史上最弱女子漫才组合，用笨拙的段子冲击全国大赛冠军。",review:"充满热血与笑声的青春物语。影片生动展现了漫才创作的艰辛与乐趣，四位女生的成长线清晰感人。笑料层出不穷，同时深刻描绘了友谊、梦想与坚持，结尾的演出段落令人热血沸腾。",region:"日韩",type:"电影",year:2021,genre:"青春励志 / 喜剧剧情",relatedIds:["0090","0072","0044","0027","0062","0052"],publishDate:"2024-02-07",summary:"在“漫才”（日本站台喜剧）文化盛行的关西地区，平凡女高中生千夏偶然被同班同学、漫才世家出身的飞鸟发现其吐槽天赋。二人连同想变得有趣的内向少女小惠，以及为了接近暗恋学长而加入的校花琉璃，组成了女子漫才组合“前说！”。她们毫无经验，写出的段子冷场，表演节奏混乱，被其他组合嘲笑为“女子高中生过家家”。但四人凭着对漫才日益增长的热爱和彼此间的支持，从校园祭走到地方预选赛，一路跌跌撞撞。面对强大的对手、学业的压力以及内心的迷茫，她们用青春特有的真诚与笨拙，创作出属于自己的搞笑风格，向着梦想的舞台全力冲刺。"},{id:77,title:"神医狂妃战神王爷乖乖受宠",cover:"19.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fbc04ae173a0e633458658e80ee78c2a/manifest/video.m3u8",category:"古装爱情",tags:["国产","电影","穿越","甜宠","爽文","医术"],rating:"8.7",views:14118,duration:"19:55",description:"现代女医穿越成懦弱王妃，一手银针救天下，一脚踹渣男，顺便收了战神王爷当跟班。",review:"典型的女强穿越爽片，节奏快，反转多，爽点密集。女主智商医术双在线，男主“追妻火葬场”的设定满足观众期待。剧情轻松下饭，是解压休闲的优质选择。",region:"国产",type:"电影",year:2024,genre:"古装爱情 / 穿越爽剧",relatedIds:["0052","0086","0042","0004","0061","0024"],publishDate:"2024-02-08",summary:"天才外科医生苏浅月意外穿越，成了南靖国备受欺凌的弃妃。原主被侧妃陷害，被王爷冷落。苏浅月醒来后，果断和离，搬出王府，凭借一手出神入化的现代医术在京城开设医馆，专治疑难杂症，名动天下。曾对她不屑一顾的战神王爷君墨寒，在边疆重伤垂危，被御医宣告不治，却被苏浅月奇迹般救回。从此，高傲的王爷化身“跟班”，整日想着如何把前王妃追回来。面对太子的觊觎、旧敌的阴谋，苏浅月与君墨寒强强联手，她以医救人，他以武护国，最终携手揭开皇室秘辛，共掌天下。"},{id:78,title:"下班啦2024",cover:"83.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/0ba4f146b0e6ea192526706f495d460f/manifest/video.m3u8",category:"都市喜剧",tags:["国产","电影","喜剧","职场","都市","社畜","友情"],rating:"9.5",views:11244,duration:"17:32",description:"互联网公司三个“卷王”好友，约定每天准时下班，探索工作之外的生活与自我。",review:"紧扣时代脉搏，精准戳中当代打工人的笑点与痛点。喜剧外壳下是对职场文化与生活意义的真诚反思。角色塑造鲜活，情感真实，能引起广泛共鸣，是一部有笑有泪的都市生活小品。",region:"国产",type:"电影",year:2024,genre:"都市喜剧 / 职场剧情",relatedIds:["0088","0042","0060","0001","0079","0069"],publishDate:"2024-02-08",summary:"在“万物皆可卷”的2024年，某大厂程序员阿强、运营阿珍和设计师大伟是公司有名的加班三巨头，也是彼此唯一的朋友。一次深夜加班，阿珍因过度疲劳晕倒送医。醒来后，三人幡然醒悟，立下“每天18：01准时下班”的军令状。从此，他们开始与上司的PUA、同事的内卷、自我的焦虑作斗争，努力 reclaim 下班后的时间。他们一起学烹饪、玩滑板、参加城市漫步、尝试相亲……在探索“生活”本身的过程中，他们重新认识了自我价值，修复了与家人的关系，也遭遇了意料之外的事业转折。最终，他们明白，“下班”不仅是一个动作，更是一种选择生活主动权的人生态度。"},{id:79,title:"魔发精灵3",cover:"29.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1e53f0e1aef7ec2fb5f30ef5d309d69c/manifest/video.m3u8",category:"动画喜剧",tags:["欧美","电影","动画","喜剧","歌舞","冒险","合家欢"],rating:"9.1",views:6817,duration:"17:22",description:"当所有精灵的魔法头发开始失去色彩，布兰和波比必须前往未知领域寻找终极救赎之歌。",review:"系列最佳，视听盛宴！音乐风格更加多元丰富，每一段冒险都对应一种独特的视听风格。故事内核关于包容、理解与团结，在绚丽多彩的动画和抓耳的音乐中传递出积极温暖的价值观。",region:"欧美",type:"电影",year:2023,genre:"动画喜剧 / 歌舞冒险",relatedIds:["0012","0061","0096","0067","0099","0018"],publishDate:"2024-02-09",summary:"精灵村的快乐庆典上，所有精灵的头发——他们快乐与魔力的源泉——突然开始失去色彩和弹性，变得灰白扁平。这意味着精灵们正在失去快乐的能力。公主波比和她的男友布兰发现，唯一能解决危机的方法是找到传说中的“终极和弦”，那是一首能恢复所有色彩与欢乐的原始歌曲。为此，他们必须离开熟悉的王国，闯入一片由完全不同的音乐风格统治的未知领域：“摇滚荒漠”、“古典云巅”、“电子迷城”。在这里，他们遇到了形形色色的新朋友和对手，必须学会欣赏和理解不同的“音乐”，才能集齐乐章，奏响拯救世界的和弦。"},{id:80,title:"孤鸟越沧海",cover:"24.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1116997bf50b78f22bbfaced8975a021/manifest/video.m3u8",category:"历史剧情",tags:["国产","电影","历史","传记","航海","冒险"],rating:"8.7",views:6292,duration:"12:41",description:"明末清初，一位中国航海家独自驾驶中式帆船，历时数载，完成跨越三大洋的壮举。",review:"影片气势恢宏，航海场面震撼人心，完美展现了人与自然的搏斗与共生。主角的孤独与坚韧被刻画得极具感染力，不仅是一次物理上的远航，更是一次精神上的朝圣，充满浪漫主义英雄色彩。",region:"国产",type:"电影",year:2022,genre:"历史剧情 / 人物传记",relatedIds:["0044","0043","0017","0027","0023","0076"],publishDate:"2024-02-09",summary:"影片基于真实历史人物改编。明末清初，航海家林沧澜因故土战乱、理想受挫，决心驾驶自己设计制造的“沧海号”帆船，独自远航，探索海外世界。他从福建出发，历经台风、海盗、疾病、孤独的考验，穿越南海、印度洋，绕过好望角，横渡大西洋。途中，他在不同港口停靠，见证了殖民贸易的兴起、各地文化的差异，也传播了东方文明。支撑他的不仅是高超的航海技术，更是内心深处对自由与探索的渴望，以及“达则兼济天下”的儒者胸怀。当他最终完成环球航行回到已是清朝的故土时，带回来的不仅是海图与见闻，更是一个超越时代的孤独梦想。"},{id:81,title:"奔跑吧兄弟第三季",cover:"81.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e398cb38b257828eeedbcaa0ae2856da/manifest/video.m3u8",category:"真人秀",tags:["国产","电影","真人秀","喜剧","竞技","综艺"],rating:"9.7",views:11315,duration:"19:05",description:"跑男团全员集结，开启全新一轮爆笑竞技之旅，挑战更刺激的任务与更强大的嘉宾。",review:"将综艺精华成功搬上大银幕，笑点密集，节奏明快，互动真实有趣。对于节目粉丝而言，是一部充满情怀和欢乐的合集；对于普通观众，也是一部轻松解压、适合全家人观看的喜剧电影。",region:"国产",type:"电影",year:2016,genre:"真人秀 / 喜剧运动",relatedIds:["0006","0071","0029","0023","0079","0028"],publishDate:"2024-02-10",summary:"本片是热门综艺《奔跑吧兄弟》第三季的精华电影版。邓超、Angelababy、李晨、陈赫、郑恺、王祖蓝、鹿晗七位固定成员悉数回归，以“热血竞技”为主题，奔赴多个城市完成高难度挑战。电影浓缩了第三季中最精彩、最爆笑的游戏环节：泥潭大战、水上撕名牌、恐怖箱挑战、以及与多位重量级嘉宾（如范冰冰、黄晓明、孙俪等）的爆笑互动。影片不仅保留了综艺的紧张刺激与欢乐氛围，更通过电影级的剪辑和叙事，突出了成员之间的默契、友情与成长，是一场为粉丝和观众打造的大银幕狂欢派对。"},{id:82,title:"爱上你是我的荣耀",cover:"51.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/77ae15566dde5cfb920bae4712a38399/manifest/video.m3u8",category:"都市爱情",tags:["国产","电影","爱情","电竞","励志","甜宠"],rating:"9.5",views:19039,duration:"11:15",description:"人气女明星乔晶晶，在游戏里重逢高中暗恋的学神于途，如今他已是心怀航天梦的工程师。",review:"将甜宠爱情与电竞、航天等正能量元素巧妙结合，格局开阔。男女主角双商在线，感情发展自然流畅，互相成就的爱情观备受好评。剧中游戏画面精良，航天线情怀满满。",region:"国产",type:"电影",year:2021,genre:"都市爱情 / 电竞励志",relatedIds:["0068","0026","0077","0039","0003","0048"],publishDate:"2024-02-10",summary:"当红女明星乔晶晶代言某款热门手游，却因游戏菜鸟身份被曝而遭遇公关危机。为挽回形象，她苦练游戏，偶然在游戏里重逢了高中时暗恋的学神于途。如今的于途，已是投身国家航天事业的工程师，也是游戏中的顶级高手。乔晶晶以“小白”身份请于途做教练，二人在虚拟世界中朝夕相处。于途被乔晶晶的真诚与努力打动，乔晶晶也更加了解于途追逐星辰大海的理想与面临的现实压力。当感情升温，他们必须面对娱乐圈与科研圈截然不同的舆论环境，以及事业与爱情的抉择。最终，他们选择彼此支持，乔晶晶用影响力传播航天精神，于途则在追逐荣耀的道路上，拥有了最温暖的港湾。"},{id:83,title:"辞职后上司和我闪婚了",cover:"56.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/41cb67b47a3668efaea014219666e659/manifest/video.m3u8",category:"都市爱情",tags:["国产","电影","爱情","喜剧","职场","闪婚","先婚后爱"],rating:"9.6",views:15964,duration:"15:49",description:"受够压榨的女下属怒辞后，在旅行中偶遇前上司，两人竟因一场意外假戏真做闪婚了。",review:"轻松浪漫的影视童话，满足职场人对“炒掉老板”和“搞定老板”的双重幻想。男女主化学反应强烈，从对立到相爱的转变有趣又甜蜜。剧情紧凑，笑点自然，是合格的解压甜点。",region:"国产",type:"电影",year:2023,genre:"都市爱情 / 浪漫喜剧",relatedIds:["0079","0069","0036","0013","0053","0063"],publishDate:"2024-02-11",summary:"林初夏在“工作狂魔”总裁陆景琛手下兢兢业业三年，最终因身心俱疲提交辞呈，决定用存款进行一场环球旅行。在冰岛的极光下，她意外邂逅了同样独自旅行的陆景琛。卸下职场身份的两人，第一次平等相处，发现了彼此不为人知的一面。旅行途中，为帮陆景琛应付家族催婚，林初夏假扮其女友，却在一系列阴差阳错和浪漫催化下，两人冲动地真的领了结婚证。回到城市，面对“前上司变老公”的尴尬，职场关系的逆转，以及两个家庭和朋友圈的震动，这对“闪婚”夫妻开始了啼笑皆非的先婚后爱生活，在磨合中探寻爱情与事业的新平衡。"},{id:84,title:"新一年又一年",cover:"40.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/31227358d3c181b7168e28ad248cfb4e/manifest/video.m3u8",category:"家庭剧情",tags:["国产","电影","家庭","年代","史诗","生活流"],rating:"9.0",views:9046,duration:"17:58",description:"透过北京胡同里陈家三代人，从1978到2025年的生活变迁，折射中国社会的沧桑巨变。",review:"一部波澜壮阔又细腻动人的平民史诗。时间跨度巨大，但细节真实可信，情感饱满。通过一个家庭微观视角，成功映射了宏大的时代变迁，引发不同年龄层观众的深刻共鸣与集体回忆。",region:"国产",type:"电影",year:2025,genre:"家庭剧情 / 年代史诗",relatedIds:["0026","0022","0091","0094","0010","0059"],publishDate:"2024-02-11",summary:"影片以编年体的形式，从1978年恢复高考讲起，每年选取一个片段，聚焦北京胡同里普通工人陈大壮一家的生活。第一代陈大壮和妻子经历工厂变革、下岗再就业；儿子陈焕作为恢复高考后的大学生，投身改革开放大潮，经历了出国、下海、创业的起伏；孙女陈晓雨则是成长于互联网时代的Z世代，面临新的机遇与困惑。故事通过年夜饭、搬家、婚丧嫁娶等家庭节点，细腻展现了物质生活的改善、思想观念的冲突与融合、代际之间的理解与隔阂。四十年时光流转，国家腾飞，个人命运随之沉浮，不变的是中国人对美好生活的向往与家庭亲情的维系。"},{id:85,title:"侧车搭档",cover:"50.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/d0af4221b8947fda8c23f4955947cb58/manifest/video.m3u8",category:"运动青春",tags:["日韩","电影","青春","竞技","运动","摩托车","女性"],rating:"9.7",views:17542,duration:"12:26",description:"两位性格迥异的高中女生，组成侧三轮摩托车竞速组合，向着全国大赛的顶点狂飙。",review:"冷门运动题材的惊喜之作。竞速场面拍摄得极具临场感和速度感，令人肾上腺素飙升。双女主的成长线与友情刻画细腻，从冲突到契合的过程真实动人，是一部热血又治愈的青春运动电影。",region:"日韩",type:"电影",year:2022,genre:"运动青春 / 竞技剧情",relatedIds:["0034","0017","0089","0003","0084","0033"],publishDate:"2024-02-12",summary:"个性冷静、拥有卓越驾驶技术的天才车手羽山遥，因无法与之前的领航员（侧车乘员）配合而陷入低谷。与此同时，活泼热血但毫无经验的转学生秋野葵，因偶然见识到侧车竞速的魅力而心生向往。在教练的撮合下，遥成为驾驶员，葵成为领航员，组成了看似极不靠谱的组合。侧车竞速需要驾驶员与领航员百分之百的信任与同步，而遥与葵从理念到性格都冲突不断。在一次次训练、失败与磨合中，她们逐渐读懂彼此的恐惧与渴望，形成了独一无二的默契。最终，这对“侧车搭档”要以女子高中生的身份，挑战由男性主导的全国大赛，用速度证明自己的实力。"},{id:86,title:"皎皎月色落孤星",cover:"91.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/e70b98acb53eb889d108057988609efb/manifest/video.m3u8",category:"古装武侠",tags:["国产","电影","武侠","权谋","爱情","虐恋"],rating:"9.0",views:15756,duration:"13:26",description:"她是敌国送来的和亲公主，他是镇守边关的冷面将军，一场政治婚姻下的试探与真心。",review:"画面极具古典美学意境，服化道精美。权谋线环环相扣，感情线含蓄而浓烈，两位主角的内心戏演绎得层次分明。家国与爱情的矛盾处理得张力十足，结局余韵悠长，令人扼腕叹息。",region:"国产",type:"电影",year:2023,genre:"古装武侠 / 权谋爱情",relatedIds:["0036","0019","0088","0064","0095","0001"],publishDate:"2024-02-12",summary:"北胤国战败，将公主慕容皎月送往南朝和亲，嫁给了令北胤闻风丧胆的镇北大将军萧星沉。新婚之夜，两人约定仅为政治合作，互不干涉。慕容皎月表面柔弱，实为心怀故国的敏锐观察者；萧星沉外表冷峻，实则在朝中遭受猜忌，如履薄冰。在同一屋檐下，两人从戒备到试探，在一次次共同应对朝堂阴谋与边境危机中，逐渐了解彼此的抱负与脆弱。皎月发现了星沉保境安民的真实理想，星沉也看穿了皎月深藏的智慧与孤独。当北胤国内乱再起，两国战火重燃，他们必须在国家大义与个人情感间做出残酷抉择。皎皎月色，终是洒落在了孤星之上。"},{id:87,title:"闪婚豪门总裁夫人马甲掉光了",cover:"88.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/86ea18f9954dbaf22eff5e16c41b4a25/manifest/video.m3u8",category:"都市爱情",tags:["国产","电影","爱情","爽剧","豪门","马甲","先婚后爱"],rating:"9.9",views:7044,duration:"19:58",description:"为救家族企业，她与豪门总裁协议结婚，婚后马甲却层层掉落：神医、黑客、杀手导师……",review:"集齐了所有爽文元素的“玛丽苏”大餐，观感极度舒适。女主“掉马甲”的过程爽点密集，男主“追妻”桥段满足幻想。剧情虽夸张但节奏带感，是放松大脑、享受甜蜜与爽感的娱乐佳作。",region:"国产",type:"电影",year:2024,genre:"都市爱情 / 豪门爽剧",relatedIds:["0018","0029","0080","0042","0050","0013"],publishDate:"2024-02-13",summary:"苏家破产，为拯救家族，苏晚被迫与传闻中冷酷无情的商业帝王傅霆深签订一年婚约。约定互不干涉，她做好乖巧花瓶。然而，傅霆深的竞争对手接连出事：下毒的被神秘解毒，黑客攻击被轻易化解，派出的杀手跪地求饶称见到“祖师爷”……傅霆深逐渐发现，自己那位看似柔弱的协议妻子，马甲多得惊人：她是隐世神医的传人，是黑客榜上的传奇“零”，更是国际某神秘组织的退休教官。傅霆深从探究到欣赏，再到深陷。当苏晚的过去仇家找上门，傅霆深毫不犹豫地站在她身前：“动我夫人，问过傅家了吗？”"},{id:88,title:"风云争霸",cover:"58.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/2df81e778442675885257ce3e84c7173/manifest/video.m3u8",category:"武侠动作",tags:["国产","电影","武侠","动作","江湖","恩怨"],rating:"8.8",views:8693,duration:"17:18",description:"天下第一铸剑师离奇身亡，其铸造的三柄神兵引发武林浩劫，正邪两道卷入争夺。",review:"传统武侠风的诚意之作，武打设计硬桥硬马，充满力量感。剧情悬念迭起，人物关系错综复杂，江湖气息浓郁。对“兵器与人欲”的探讨有一定深度，是千禧年初武侠片的典型代表。",region:"国产",type:"电影",year:2004,genre:"武侠动作 / 江湖恩怨",relatedIds:["0055","0001","0028","0020","0067","0013"],publishDate:"2024-02-13",summary:"天下第一铸剑师欧冶子耗费毕生心血，铸成“天怒”、“地怨”、“人殇”三柄绝世神兵后离奇暴毙。传闻得齐三剑者可获得剑中隐藏的无上武功秘笈，一统江湖。一时间，正邪各派、朝廷势力纷纷卷入这场血腥争夺。青年侠客凌霄因其师门与欧冶子有旧，被卷入漩涡中心。他结识了身份神秘的女剑客雪魄，并与亦正亦邪的魔教之子韩飞成为亦敌亦友的关系。在追寻神兵与真相的过程中，凌霄发现师父之死、自己身世乃至二十年前的一桩武林公案，都与这三柄剑息息相关。最终，为阻止浩劫，他必须做出超越正邪之分的抉择。"},{id:89,title:"不老梦想家",cover:"71.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/af3d3f3b4940cee04efcd8ff2c9eef0a/manifest/video.m3u8",category:"奇幻",tags:["国产","电影","奇幻","温情","人生","家庭"],rating:"9.5",views:12934,duration:"11:56",description:"七位平均年龄75岁的老人，意外获得短暂重返青春的机会，决定合力追寻年少时未竟的疯狂梦想。",review:"影片以奇幻设定包裹深沉的人文关怀，节奏明快又充满温情泪点。老年与青年状态的巧妙碰撞产生了大量幽默与思考，让观众在欢笑中体味人生的厚重与梦想的璀璨。设定新颖，情感真挚，是一部能治愈人心的佳作。",region:"国产",type:"电影",year:2023,genre:"奇幻 / 剧情 / 家庭",relatedIds:["0015","0016","0036","0085","0005","0047"],publishDate:"2024-02-14",summary:"在南方一个宁静的养老社区里，七位性格迥异、暮气沉沉的老人，因一场神秘的流星雨获得了“重返青春七日”的奇迹。他们变回了自己25岁时的模样，但心智与记忆依旧属于老年。面对这突如其来的第二次机会，有人想弥补对初恋的遗憾，有人想完成环球旅行的夙愿，有人则想站在舞台上唱一次摇滚。七人组成了“不老梦想团”，在有限的时间里展开了一场与时间赛跑的圆梦之旅。过程中，他们不仅重新体验了青春的活力与激情，更在彼此的扶持与“代际”冲突中，深刻理解了梦想与年龄无关，而关乎勇气与爱的真谛。最终，他们留给彼此的，是一段永不褪色的闪耀记忆。"},{id:90,title:"农场小牛牛",cover:"94.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/60b4ddb3d166e1239abfc7adf611a6a3/manifest/video.m3u8",category:"动画",tags:["欧美","电影","动画","喜剧","冒险","合家欢"],rating:"10.0",views:11139,duration:"17:05",description:"一头梦想成为超级英雄的小牛，为拯救被收购的农场，踏上了招募“超能农场动物联盟”的爆笑征程。",review:"色彩明快，角色可爱，笑点密集且适合全年龄段。影片将英雄叙事与田园风情完美结合，在轻松欢乐的冒险中探讨了勇气、自我认同与环境保护的主题，寓教于乐，充满正能量。",region:"欧美",type:"电影",year:2015,genre:"动画 / 喜剧 / 冒险",relatedIds:["0014","0088","0027","0028","0062","0069"],publishDate:"2024-02-14",summary:"在阳光灿烂的哞哞农场，小牛“力力”不爱吃草爱看超级英雄漫画，坚信自己体内蕴藏着拯救世界的力量。当农场面临被大型农业公司收购改造的危机时，力力决定挺身而出。它说服了认为自己只会下蛋的母鸡“飞飞”、害怕自己獠牙的野猪“壮壮”、以及一只自称见过世面的老山羊“智多星”，组成了临时“超能联盟”。它们的冒险从农场仓库开始，一路经历了城市下水道、喧嚣的集市，甚至误闯入一个科技博览会。在一连串令人捧腹的失败和意外中，它们发现真正的“超能力”并非蛮力或特异功能，而是友谊、智慧与守护家园的坚定决心。最终，动物们用独特的方式，向人们证明了传统农场的价值与温情。"},{id:91,title:"绝叫",cover:"70.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/a27121d514ff0079e1e81a6678f14e0c/manifest/video.m3u8",category:"犯罪",tags:["日韩","电影","犯罪","悬疑","社会","人性"],rating:"9.8",views:10924,duration:"16:15",description:"一名女子在长期遭受社会与家庭挤压后，于沉默中爆发的极致犯罪，揭示现代人的生存困境。",review:"叙事冷静克制，极具现实主义震撼力。对社会病灶的剖析入木三分，女主角的蜕变过程令人窒息又心生怜悯。节奏张弛有度，悬念保持到最后，是一部发人深省的社会派犯罪杰作。",region:"日韩",type:"电影",year:2021,genre:"犯罪 / 悬疑 / 社会",relatedIds:["0019","0081","0015","0097","0057","0046"],publishDate:"2024-02-15",summary:"改编自社会派推理小说。主人公阳子从小在重男轻女的家庭中长大，成年后经历婚姻破裂、职场欺凌、保险欺诈等一系列绝望打击，人生不断下坠。影片以阳子涉及的多起离奇死亡事件为线索，通过一位执着刑警的视角和阳子本人的回忆双线交织，层层剥开她如何从一个普通的职场女性，一步步被社会巨轮碾压、异化，最终走向犯罪深渊的悲剧过程。故事不仅仅是一场犯罪的追查，更是一幅描绘日本社会泡沫经济破裂后，普通人尤其是女性生存艰难的浮世绘。结局的惊天反转，不仅关乎案情真相，更指向了整个社会结构的冷漠与残酷。"},{id:92,title:"一袋弹子",cover:"32.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/f0d38b8679a1231eff816a8e04cc1a0c/manifest/video.m3u8",category:"战争",tags:["欧美","电影","战争","剧情","历史","犹太"],rating:"9.3",views:10807,duration:"14:38",description:"二战期间，一对年轻的犹太兄弟靠着一袋弹子作为信物，在法国展开了一场惊心动魄的求生逃亡。",review:"以儿童视角切入沉重历史，举重若轻，情感真挚动人。兄弟情谊刻画细腻，逃亡过程悬念迭起。影片在展现战争残酷的同时，更歌颂了生命的坚韧与人性中的善良，感人至深。",region:"欧美",type:"电影",year:2017,genre:"战争 / 剧情 / 历史",relatedIds:["0098","0032","0018","0081","0046","0091"],publishDate:"2024-02-15",summary:"影片根据法国犹太裔作家约瑟夫·若福的同名回忆录改编。1941年，德军占领下的巴黎，10岁的乔和12岁的莫里斯被迫与家人分离，开始了长达数年的逃亡生涯。父亲交给他们一袋弹子，叮嘱这是家族的信物，也是活下去的信念象征。两兄弟凭着机智、勇气和陌生人的善意，穿越封锁线，躲避纳粹搜捕，从巴黎到尼斯，再到法国南部的村庄。他们伪装成非犹太裔儿童，经历了无数次命悬一线的危机，也见证了战争中人性的光辉与黑暗。那袋弹子不仅是游戏玩具，更是连接亲情、象征希望与不屈精神的珍贵之物，支撑他们最终盼来了与家人的重逢。"},{id:93,title:"自杀四人组",cover:"13.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c66b5309b3b64d15ed856810d6cc0b72/manifest/video.m3u8",category:"黑色喜剧",tags:["国产","电影","黑色喜剧","剧情","治愈","人生"],rating:"8.6",views:16336,duration:"14:15",description:"四个在除夕夜相约赴死陌生人，却因一场荒诞意外组成“互阻小队”，重新发现生命的意义。",review:"题材大胆，以极高明的幽默感处理沉重主题，笑中带泪，泪中有光。角色塑造鲜明，对话精彩，在荒诞的情境中探讨了生命、孤独与联结的深刻命题，治愈力量强大。",region:"国产",type:"电影",year:2024,genre:"黑色喜剧 / 剧情",relatedIds:["0017","0025","0047","0020","0054","0087"],publishDate:"2024-02-16",summary:"新年前夕，四位因不同原因对生活绝望的陌生人——破产的中年老板、患绝症的教师、被网暴的网红、孤独的空巢老人，不约而同来到城市边缘的废弃观景台准备自杀。然而，一场突如其来的小地震打断了他们的计划，四人被困在摇摇欲坠的观景台上。在等待救援的漫漫长夜里，从最初的尴尬沉默到被迫交流，他们互相揭露了各自想要结束生命的痛苦原因。出于一种荒诞的“不能让任何人抢先”的心理，他们竟然形成了互相监督、阻止对方自杀的临时同盟。在求生与求死的矛盾交织中，一系列啼笑皆非又温暖动人的故事发生，让他们重新审视了绝望背后的渴望，并在彼此身上找到了意外的羁绊与活下去的微小理由。"},{id:94,title:"寒枝折不断电影版",cover:"96.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/c99d86ece73a935b77e57d322461ddb5/manifest/video.m3u8",category:"古装",tags:["国产","电影","古装","武侠","爱情","虐恋"],rating:"8.9",views:18178,duration:"12:26",description:"锦衣卫与女刺客在阴谋与风雪中相爱相杀，一段在权柄与刀锋上艰难绽放的禁忌之恋。",review:"电影版制作升级，画面极具东方美学，雪景打斗场面诗意而凌厉。男女主情感刻画细腻深沉，权谋线与感情线交织紧密，虐恋感十足。结局荡气回肠，令人回味。",region:"国产",type:"电影",year:2022,genre:"古装 / 武侠 / 爱情",relatedIds:["0017","0078","0089","0068","0071","0064"],publishDate:"2024-02-16",summary:"电影版扩展了剧集的世界观。明朝嘉靖年间，冷酷高效的锦衣卫千户张寂，奉命追查一桩涉及皇室秘闻的连环刺杀案，目标直指神秘组织“暗香”的女刺客李寒枝。在一次次生死交锋与智谋较量中，两人逐渐被对方的能力与坚持所吸引，暗生情愫。然而，张寂的上司、东厂督主对“暗香”有着更深的图谋，而李寒枝的身世也与皇室阴谋紧密相连。风雪凛冽的边关小镇，两人在明知彼此立场对立、前路危机四伏的情况下，仍无法割舍这份感情。他们如同在寒冬中艰难求生的枝条，既要抵抗外部的风雪摧折，也要面对内心忠诚与爱情的剧烈撕扯，最终不得不做出震撼朝野的抉择。"},{id:95,title:"他在窥着你",cover:"41.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fe0c41d994d01211debb24e84e3384a9/manifest/video.m3u8",category:"惊悚",tags:["日韩","电影","惊悚","心理","犯罪","偷窥"],rating:"8.8",views:18090,duration:"17:21",description:"独居女子发现对面邻居每晚用望远镜窥视自己，一场反客为主的危险心理博弈悄然开始。",review:"氛围营造堪称一流，将日常空间拍出了令人窒息的压迫感。心理刻画细致入微，女主角从恐惧到反抗再到沉溺的转变过程极具说服力。剧情多次反转，结局出人意料，是心理惊悚片的佳作。",region:"日韩",type:"电影",year:2019,genre:"惊悚 / 心理 / 犯罪",relatedIds:["0027","0089","0017","0074","0045","0007"],publishDate:"2024-02-17",summary:"刚搬入新公寓的自由撰稿人苏莹，渐渐感到一种莫名的不安。她发现对面楼的男邻居金先生，似乎总在夜晚用望远镜望向她的窗户。起初她选择报警和加强防备，但警方因证据不足无法介入。在恐惧与愤怒的驱使下，苏莹决定不再被动逃避。她开始反向观察金先生的生活，利用写作的洞察力分析他的行为模式，甚至故意设计一些场景来试探和挑衅。这场“看与被看”的角力逐渐升级，苏莹发现自己似乎沉浸在这种危险的对抗中，而金先生的真实目的和他屋内隐藏的秘密，远比单纯的偷窥更加惊悚。当界线越来越模糊，谁才是真正的猎物，谁又是猎人？"},{id:96,title:"超级男女",cover:"64.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/929fdb8e536c1fc43a83b32d1a838547/manifest/video.m3u8",category:"爱情",tags:["国产","电影","爱情","喜剧","奇幻","都市"],rating:"9.3",views:18306,duration:"11:20",description:"一场雷击让一对冤家互换了超能力，他们必须合作才能拯救城市，并面对错位的感情。",review:"典型的都市奇幻喜剧，创意有趣，笑点密集。男女主角化学反应十足，从互怼到合作的转变自然有趣。动作与爱情元素结合得当，是一部轻松愉快的娱乐大片。",region:"国产",type:"电影",year:2008,genre:"爱情 / 喜剧 / 奇幻",relatedIds:["0045","0014","0069","0048","0095","0059"],publishDate:"2024-02-17",summary:"雷小明是消防队里胆大冒失的“拆弹专家”，杜拉拉是博物馆一丝不苟的古画修复师，两人因一次相亲闹剧成为水火不容的冤家。一场罕见的球状闪电同时击中二人，导致他们的身体发生了奇妙变化：雷小明获得了能看透物体内部结构的“微观眼”，而杜拉拉则变得力大无穷。起初他们被自己的能力弄得焦头烂额，笑料百出。此时，一伙国际艺术品大盗盯上了博物馆的镇馆之宝，其盗窃手法高科技且隐秘。唯一能看穿伪装的是雷小明的“微观眼”，而能突破重重机关则需要杜拉拉的“神力”。在安全部门的协调下，这对超级冤家被迫组成搭档。在合作破案的过程中，他们逐渐理解了对方的世界，错位的能力也催生了错位的心动。"},{id:97,title:"刺青粤语",cover:"49.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/fbc04ae173a0e633458658e80ee78c2a/manifest/video.m3u8",category:"剧情",tags:["日韩","电影","剧情","爱情","同性","文艺"],rating:"9.6",views:10060,duration:"13:22",description:"性格迥异的刺青师与高中生因一次纹身相遇，在肌肤的疼痛与色彩的渗透中，刻下隐秘的情感。",review:"影片充满日式美学风格，画面静谧而富有张力。情感描写细腻含蓄，纹身的过程被隐喻为情感渗透与灵魂交融。两位女主的表演内敛而深刻，音乐与氛围极佳，是一部后劲十足的文艺佳作。",region:"日韩",type:"电影",year:2006,genre:"剧情 / 爱情 / 同性",relatedIds:["0012","0011","0019","0045","0071","0091"],publishDate:"2024-02-18",summary:"在福冈的沿海小镇，有一位技艺精湛却沉默寡言的女性刺青师阿静，她的工作室隐藏在小巷深处，只为真正懂的人服务。高中生小枫因想遮盖童年伤疤，辗转找到了阿静。纹身的过程缓慢而疼痛，在肌肤被一点点描绘的过程中，小枫向阿静吐露了关于家庭、校园和身份认同的烦恼，而阿静则以简短的回应和专注的眼神作为反馈。小枫被阿静神秘的气质和艺术世界所吸引，频繁来访，从顾客变成了助手，再变成生活中无法割舍的一部分。两人之间的情感在氤氲的草药味、针机的嗡鸣与色彩的融合中悄然滋生。然而，阿静不愿提及的过去和小枫即将到来的升学压力，为这段关系蒙上了不确定性。他们用刺青铭记，也用刺青逃避。"},{id:98,title:"疯狂动物园",cover:"12.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/0ba4f146b0e6ea192526706f495d460f/manifest/video.m3u8",category:"喜剧",tags:["欧美","电影","动画","喜剧","冒险","合家欢"],rating:"9.7",views:6572,duration:"11:52",description:"一只有洁癖的考拉为拯救濒临倒闭的祖传动物园，被迫与一群“问题动物”员工联手搞事。",review:"笑点高级且持续不断，动物角色性格鲜明可爱，充满了美式动画的活力与想象力。故事在搞笑之余，也巧妙地传达了接纳自我、拥抱不同的积极主题，适合全家观看。",region:"欧美",type:"电影",year:2011,genre:"喜剧 / 动画 / 冒险",relatedIds:["0030","0001","0044","0011","0031","0020"],publishDate:"2024-02-18",summary:"大都市边缘的“花花动物园”历史悠久却门可罗雀，园长是继承家业的年轻考拉“花花”，它有严重洁癖和管理恐惧症。债主给的最后通牒是：如果下个月游客量不能翻十倍，动物园就将被改建成高尔夫球场。走投无路的花花，在神秘老乌龟的建议下，不得不启用园里那些一直因“性格缺陷”被雪藏的动物：患有表演焦虑的魔术师猴子、总在梦游的树懒保安、愤世嫉俗的摇滚鹦鹉、以及一只坚信自己是企鹅的北极熊。这群乌合之众组成的“拯救小队”，策划了一系列令人瞠目结舌的疯狂营销活动，从夜间恐怖之旅到动物主题摇滚音乐会，闹出了无数笑话，但也意外地让动物园成为了网络焦点。他们最终发现，所谓的“缺陷”，正是每个个体最独特的魅力。"},{id:99,title:"无上尊者",cover:"74.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1e53f0e1aef7ec2fb5f30ef5d309d69c/manifest/video.m3u8",category:"玄幻",tags:["国产","电影","玄幻","动作","剧情","东方奇幻"],rating:"8.9",views:13338,duration:"17:23",description:"末法时代，一名被废修为的尊者以凡人之躯重走修行路，挑战整个腐朽的仙界秩序。",review:"构建了独具一格的东方玄幻世界观，设定新颖深刻。动作场面兼具写意与震撼，特效精美。主角的成长弧光完整，从人到神再回归于人道的思想蜕变发人深省，超越了一般玄幻片的框架。",region:"国产",type:"电影",year:2025,genre:"玄幻 / 动作 / 剧情",relatedIds:["0068","0069","0084","0016","0073","0071"],publishDate:"2024-02-19",summary:"在灵气枯竭、法则僵化的末法时代，仙界由四大天尊把持，等级森严。曾经的“无上尊者”凌霄因质疑天道不公、欲破旧立新，被剥夺仙骨，打落凡尘，记忆尽失，成为一个名叫林晓的普通青年。在人间，他经历生老病死、爱别离、怨憎会，体会到了仙界早已遗忘的“人性”。一次偶然，他体内残存的一丝本源道种被唤醒，开始以截然不同的方式重新修炼——不依赖灵气，而感悟人间百态、红尘因果。他的崛起引起了仙界的警惕与追杀。随着记忆逐渐复苏，林晓发现当年的“罪责”背后隐藏着关乎三界存亡的巨大阴谋。他必须集结人间志士，以全新的“人道”修炼体系，向高高在上的旧神发起终极挑战。"},{id:100,title:"查理布朗，跟着小猎犬一起来热舞吧！",cover:"23.jpg",videoUrl:"https://customer-7t103rn8rocxo5v6.cloudflarestream.com/1116997bf50b78f22bbfaced8975a021/manifest/video.m3u8",category:"动画",tags:["欧美","电影","动画","歌舞","喜剧","史努比"],rating:"9.2",views:19791,duration:"17:16",description:"史努比梦见举办一场盛大的森林舞会，查理布朗和朋友们全力助阵，却引发一连串混乱与惊喜。",review:"完美继承了《花生漫画》的温馨幽默气质，歌舞场面充满想象力与童趣。角色性格鲜明，笑料自然不做作。影片传递了“不必完美，开心就好”的简单快乐，是一部能让人会心一笑的治愈系作品。",region:"欧美",type:"电影",year:2021,genre:"动画 / 歌舞 / 喜剧",relatedIds:["0099","0027","0013","0080","0096","0092"],publishDate:"2024-02-19",summary:"在一个慵懒的夏日，史努比躺在狗屋上做了一个华丽的梦：它成为森林舞会的明星主持，而查理布朗是它的最佳舞伴。梦醒后，它决定将梦想照进现实，在后院举办一场真正的“超级狗狗热舞派对”。查理布朗虽然对跳舞一窍不通，但为了不让好朋友失望，还是硬着头皮答应了。消息传出，佩蒂、露西、莱纳斯等朋友们都热情（或别扭）地参与进来，各自准备节目，结果自然是状况百出：莱纳斯的安全毯成了舞蹈道具，露西的指挥引发争吵，而查理布朗的笨拙似乎无可救药。与此同时，史努比和糊涂塌客也在为舞会的灯光、音乐（当然是想象出来的）忙碌。最终，这场计划中的“完美舞会”变成了一场充满意外、真诚与欢笑的狂欢，每个人（和狗）都找到了属于自己的节奏。"}],r=[{id:"____",name:"爱情剧情",description:"爱情剧情类型影视作品"},{id:"___",name:"纪录片",description:"纪录片类型影视作品"},{id:"____",name:"恐怖惊悚",description:"恐怖惊悚类型影视作品"},{id:"____",name:"悬疑探案",description:"悬疑探案类型影视作品"},{id:"____",name:"爱情喜剧",description:"爱情喜剧类型影视作品"},{id:"__",name:"剧情",description:"剧情类型影视作品"},{id:"____",name:"科幻悬疑",description:"科幻悬疑类型影视作品"},{id:"____",name:"奇幻喜剧",description:"奇幻喜剧类型影视作品"},{id:"____",name:"校园青春",description:"校园青春类型影视作品"},{id:"____",name:"古装动作",description:"古装动作类型影视作品"}],t={videos:e,categories:r};export{r as categories,t as default,e as videos};
